import React from 'react';
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  Cell
} from 'recharts';
import { FETISH_DATA } from '../constants';

const TrendChart: React.FC = () => {
  const data = FETISH_DATA.map(f => ({
    name: f.title.split(' ')[0], // Shorten name
    fullTitle: f.title,
    popularity: f.popularity,
  })).sort((a, b) => b.popularity - a.popularity);

  return (
    <div className="w-full h-[300px] md:h-[400px] bg-dark-800/50 rounded-xl p-4 border border-brand-900/30">
      <h3 className="text-brand-300 mb-4 font-semibold text-sm uppercase tracking-wider">
        Tendências Nacionais 2025/2026 (%)
      </h3>
      <ResponsiveContainer width="100%" height="100%">
        <BarChart
          data={data}
          margin={{
            top: 5,
            right: 10,
            left: -20,
            bottom: 5,
          }}
        >
          <CartesianGrid strokeDasharray="3 3" stroke="#333" vertical={false} />
          <XAxis 
            dataKey="name" 
            stroke="#9ca3af" 
            tick={{ fontSize: 10 }} 
            interval={0}
            angle={-45}
            textAnchor="end"
            height={60}
          />
          <YAxis stroke="#9ca3af" tick={{ fontSize: 12 }} />
          <Tooltip 
            contentStyle={{ backgroundColor: '#18181b', borderColor: '#831843', color: '#f4f4f5' }}
            itemStyle={{ color: '#f472b6' }}
            cursor={{ fill: '#831843', opacity: 0.2 }}
          />
          <Bar dataKey="popularity" radius={[4, 4, 0, 0]}>
            {data.map((entry, index) => (
              <Cell key={`cell-${index}`} fill={index < 3 ? '#db2777' : '#831843'} />
            ))}
          </Bar>
        </BarChart>
      </ResponsiveContainer>
    </div>
  );
};

export default TrendChart;

import React, { useState } from 'react';
import { GoogleGenAI } from "@google/genai";
import { MessageCircle, Send, Sparkles, X } from 'lucide-react';

const GeminiAdvisor: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<{ role: 'user' | 'model'; text: string }[]>([
    { role: 'model', text: 'Olá. Sou seu assistente de educação sexual segura. Tem alguma dúvida sobre os guias ou práticas?' }
  ]);
  const [loading, setLoading] = useState(false);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setLoading(true);

    try {
      const apiKey = process.env.API_KEY || '';
      // Fail gracefully if no key (demo mode)
      if (!apiKey) {
         setTimeout(() => {
            setMessages(prev => [...prev, { role: 'model', text: 'Nota: API Key não configurada neste ambiente de demonstração. Em produção, eu responderia usando Gemini.' }]);
            setLoading(false);
         }, 1000);
         return;
      }

      const ai = new GoogleGenAI({ apiKey });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `You are a professional, discreet, and educational sexual wellness advisor for a Brazilian app called "KinkMaster". 
        The user is asking: "${userMsg}". 

        Rules:
        1. Keep answers concise (max 3 sentences).
        2. Be sex-positive, inclusive (LGBT+ friendly), and focus on consent and safety.
        3. Do not be explicit in a pornographic way; use clinical or educational terms.
        4. Recommend checking the app's guides for deep dives.
        5. Answer in Portuguese.`,
      });

      const text = response.text || "Desculpe, não consegui processar sua pergunta no momento.";
      setMessages(prev => [...prev, { role: 'model', text }]);

    } catch (error) {
      console.error(error);
      setMessages(prev => [...prev, { role: 'model', text: "Erro ao conectar com o assistente. Tente novamente." }]);
    } finally {
      setLoading(false);
    }
  };

  if (!isOpen) {
    return (
      <button 
        onClick={() => setIsOpen(true)}
        className="fixed bottom-6 right-6 bg-brand-600 hover:bg-brand-500 text-white p-4 rounded-full shadow-lg shadow-brand-900/50 transition-all z-50 flex items-center gap-2 group"
      >
        <Sparkles size={20} className="animate-pulse" />
        <span className="font-semibold hidden group-hover:block transition-all">Dúvidas?</span>
      </button>
    );
  }

  return (
    <div className="fixed bottom-6 right-6 w-80 md:w-96 bg-dark-800 border border-brand-800 rounded-2xl shadow-2xl z-50 flex flex-col overflow-hidden max-h-[500px]">
      {/* Header */}
      <div className="bg-brand-900 p-4 flex justify-between items-center">
        <div className="flex items-center gap-2 text-white">
          <Sparkles size={18} />
          <h3 className="font-bold text-sm">IA Advisor (Beta)</h3>
        </div>
        <button onClick={() => setIsOpen(false)} className="text-brand-200 hover:text-white">
          <X size={18} />
        </button>
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto p-4 space-y-3 bg-dark-900/50">
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] p-3 rounded-xl text-sm ${
              m.role === 'user' 
                ? 'bg-brand-700 text-white rounded-tr-none' 
                : 'bg-dark-700 text-gray-200 rounded-tl-none border border-dark-600'
            }`}>
              {m.text}
            </div>
          </div>
        ))}
        {loading && <div className="text-xs text-brand-400 animate-pulse ml-2">Digitando...</div>}
      </div>

      {/* Input */}
      <div className="p-3 bg-dark-800 border-t border-dark-700 flex gap-2">
        <input 
          type="text" 
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyPress={(e) => e.key === 'Enter' && handleSend()}
          placeholder="Pergunte sobre segurança..."
          className="flex-1 bg-dark-900 border border-dark-600 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:border-brand-500"
        />
        <button 
          onClick={handleSend}
          disabled={loading}
          className="bg-brand-600 hover:bg-brand-500 text-white p-2 rounded-lg transition-colors disabled:opacity-50"
        >
          <Send size={18} />
        </button>
      </div>
    </div>
  );
};

