import React, { useState } from 'react';
import { FetishData, TargetAudience } from '../types';
import { Check, X, ArrowRight, ShieldCheck, Lock, CreditCard } from 'lucide-react';

interface Props {
  fetish: FetishData;
  onClose: () => void;
  onUnlock: (fetishId: string, audience: TargetAudience) => void;
}

type Step = 'select_audience' | 'product_view' | 'checkout_bump' | 'upsell' | 'success';

const ProductFlow: React.FC<Props> = ({ fetish, onClose, onUnlock }) => {
  const [step, setStep] = useState<Step>('select_audience');
  const [audience, setAudience] = useState<TargetAudience>('Homens');
  const [hasBump, setHasBump] = useState(false);
  const [hasUpsell, setHasUpsell] = useState(false);

  const product = fetish.products[audience];
  const basePrice = 47;
  const bumpPrice = product.bumpPrice;
  const upsellPrice = 197;

  const handlePurchase = () => {
    // Simulate API call
    setTimeout(() => {
      setStep('upsell');
    }, 800);
  };

  const handleUpsell = (accepted: boolean) => {
    if (accepted) {
      setHasUpsell(true);
      setStep('success');
    } else {
        setStep('success');
    }
  };

  const handleFinish = () => {
      onUnlock(fetish.id, audience);
  };

  const calculateTotal = () => {
    let total = basePrice;
    if (hasBump) total += bumpPrice;
