import React, { useState } from 'react';
import { GoogleGenAI } from "@google/genai";
import { MessageCircle, Send, Sparkles, X, Lock, Crown } from 'lucide-react';

interface Props {
  isSubscribed: boolean;
  onSubscribe: () => void;
}

const GeminiAdvisor: React.FC<Props> = ({ isSubscribed, onSubscribe }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<{ role: 'user' | 'model'; text: string }[]>([
    { role: 'model', text: 'Olá. Sou seu Mentor IA pessoal. Como posso ajudar na sua jornada de exploração hoje?' }
  ]);
  const [loading, setLoading] = useState(false);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setLoading(true);

    try {
      const apiKey = process.env.API_KEY || '';
      // Fail gracefully if no key (demo mode)
      if (!apiKey) {
         setTimeout(() => {
            setMessages(prev => [...prev, { role: 'model', text: 'Nota: API Key não configurada neste ambiente de demonstração. Em produção, eu responderia usando Gemini.' }]);
            setLoading(false);
         }, 1000);
         return;
      }

      const ai = new GoogleGenAI({ apiKey });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `You are a professional, discreet, and educational sexual wellness advisor for a Brazilian app called "KinkMaster". 
        The user is asking: "${userMsg}". 

        Rules:
        1. Keep answers concise (max 3 sentences).
        2. Be sex-positive, inclusive (LGBT+ friendly), and focus on consent and safety.
        3. Do not be explicit in a pornographic way; use clinical or educational terms.
        4. Recommend checking the app's guides for deep dives.
        5. Answer in Portuguese.`,
      });

      const text = response.text || "Desculpe, não consegui processar sua pergunta no momento.";
      setMessages(prev => [...prev, { role: 'model', text }]);

    } catch (error) {
      console.error(error);
      setMessages(prev => [...prev, { role: 'model', text: "Erro ao conectar com o assistente. Tente novamente." }]);
    } finally {
      setLoading(false);
    }
  };

  if (!isOpen) {
    return (
      <button 
        onClick={() => setIsOpen(true)}
        className="fixed bottom-6 right-6 bg-brand-600 hover:bg-brand-500 text-white p-4 rounded-full shadow-lg shadow-brand-900/50 transition-all z-50 flex items-center gap-2 group"
      >
        {isSubscribed ? <Sparkles size={20} className="animate-pulse" /> : <Lock size={20} />}
        <span className="font-semibold hidden group-hover:block transition-all">
            {isSubscribed ? 'Mentor IA' : 'Dúvidas?'}
        </span>
      </button>
    );
  }

  return (
    <div className="fixed bottom-6 right-6 w-80 md:w-96 bg-dark-800 border border-brand-800 rounded-2xl shadow-2xl z-50 flex flex-col overflow-hidden max-h-[500px]">
      {/* Header */}
      <div className="bg-brand-900 p-4 flex justify-between items-center shrink-0">
        <div className="flex items-center gap-2 text-white">
          {isSubscribed ? <Sparkles size={18} /> : <Lock size={18} />}
          <h3 className="font-bold text-sm">Mentor IA {isSubscribed ? '(Ativo)' : '(Bloqueado)'}</h3>
        </div>
        <button onClick={() => setIsOpen(false)} className="text-brand-200 hover:text-white">
          <X size={18} />
        </button>
      </div>

      {!isSubscribed ? (
        // LOCKED STATE
        <div className="p-6 flex flex-col items-center text-center h-[400px] justify-center bg-dark-900 relative overflow-hidden">
            <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')] opacity-10"></div>

            <div className="w-16 h-16 bg-dark-800 rounded-full flex items-center justify-center mb-4 border border-brand-900 relative z-10">
                <Crown size={32} className="text-brand-500" />
            </div>

            <h3 className="text-xl font-bold text-white mb-2 relative z-10">Exclusivo para o Club</h3>
            <p className="text-gray-400 text-sm mb-6 relative z-10">
                Acesso ilimitado ao Mentor IA para tirar dúvidas sobre práticas, segurança e roteiros personalizados.
            </p>

            <button 
                onClick={() => { setIsOpen(false); onSubscribe(); }}
                className="w-full py-3 bg-brand-600 hover:bg-brand-500 text-white rounded-xl font-bold transition-all shadow-lg shadow-brand-900/20 relative z-10"
            >
                Liberar Acesso Agora
            </button>
            <p className="text-xs text-gray-500 mt-4 relative z-10">Apenas R$ 29,90/mês</p>
        </div>
      ) : (
        // UNLOCKED STATE (Chat Interface)
        <>
            <div className="flex-1 overflow-y-auto p-4 space-y-3 bg-dark-900/50 h-[350px]">
                {messages.map((m, i) => (
                <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                    <div className={`max-w-[85%] p-3 rounded-xl text-sm ${
                    m.role === 'user' 
                        ? 'bg-brand-700 text-white rounded-tr-none' 
                        : 'bg-dark-700 text-gray-200 rounded-tl-none border border-dark-600'
                    }`}>
                    {m.text}
                    </div>
                </div>
                ))}
                {loading && <div className="text-xs text-brand-400 animate-pulse ml-2">Digitando...</div>}
            </div>

            {/* Input */}
            <div className="p-3 bg-dark-800 border-t border-dark-700 flex gap-2 shrink-0">
                <input 
                type="text" 
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyPress={(e) => e.key === 'Enter' && handleSend()}
                placeholder="Pergunte sobre segurança..."
                className="flex-1 bg-dark-900 border border-dark-600 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:border-brand-500"
                />
                <button 
                onClick={handleSend}
                disabled={loading}
                className="bg-brand-600 hover:bg-brand-500 text-white p-2 rounded-lg transition-colors disabled:opacity-50"
                >
                <Send size={18} />
                </button>
            </div>
        </>
      )}
    </div>
  );
};

