import { Flame, Lock, User, Crown } from 'lucide-react';

const App: React.FC = () => {
  // Initialize from localStorage if available, otherwise default to ['anal']
  const [unlockedIds, setUnlockedIds] = useState<string[]>(() => {
    try {
      const saved = localStorage.getItem('kinkmaster_unlocked');
      return saved ? JSON.parse(saved) : ['anal'];
    } catch (e) {
      return ['anal'];
    }
  });

  const [isSubscribed, setIsSubscribed] = useState<boolean>(() => {
    try {
        return localStorage.getItem('kinkmaster_subscribed') === 'true';
    } catch (e) { return false; }
  });

  // Navigation State
  const [view, setView] = useState<'dashboard' | 'player'>('dashboard');

  // Selection State
  const [selectedLockedFetish, setSelectedLockedFetish] = useState<FetishData | null>(null);
  const [currentCourse, setCurrentCourse] = useState<{fetish: FetishData, audience: TargetAudience} | null>(null);
  const [showSubscriptionModal, setShowSubscriptionModal] = useState(false);

  // Effect to save to localStorage
  useEffect(() => {
    localStorage.setItem('kinkmaster_unlocked', JSON.stringify(unlockedIds));
  }, [unlockedIds]);

  useEffect(() => {
    localStorage.setItem('kinkmaster_subscribed', String(isSubscribed));
  }, [isSubscribed]);

  const handleUnlock = (fetishId: string, audience: TargetAudience) => {
    setUnlockedIds(prev => {
      if (prev.includes(fetishId)) return prev;
      return [...prev, fetishId];
    });
    setSelectedLockedFetish(null);
    const fetish = FETISH_DATA.find(f => f.id === fetishId);
    if (fetish) {
      setCurrentCourse({ fetish, audience });
      setView('player');
    }
  };

  const handleSelectUnlocked = (fetish: FetishData) => {
    setCurrentCourse({ fetish, audience: 'Homens' });
    setView('player');
  };

  const handleSubscribe = () => {
      // Simulate payment processing
      setTimeout(() => {
          setIsSubscribed(true);
          setShowSubscriptionModal(false);
      }, 1000);
  };

  if (view === 'player' && currentCourse) {
    return (
      <CoursePlayer 
        fetish={currentCourse.fetish} 
        audience={currentCourse.audience}
        onBack={() => setView('dashboard')} 
      />
    );
  }

  return (
    <div className="min-h-screen bg-dark-900 text-gray-100 font-sans selection:bg-brand-900 selection:text-white">
      {/* Header */}
      <header className="border-b border-dark-800 bg-dark-900/95 backdrop-blur sticky top-0 z-40">
        <div className="container mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2 cursor-pointer" onClick={() => setView('dashboard')}>
            <Flame className="text-brand-500" />
            <span className="font-bold text-xl tracking-tight text-white">Kink<span className="text-brand-500">Master</span></span>
