               </div>
             </div>
             <div className={`w-10 h-10 rounded-full border flex items-center justify-center ${isSubscribed ? 'bg-brand-900 border-brand-500 text-brand-200' : 'bg-dark-800 border-dark-700 text-gray-400'}`}>
                <User size={20} />
             </div>
          </div>
        </div>
      </header>

      <main className="container mx-auto px-4 py-8 md:py-12">

        {/* Welcome Banner */}
        <section className="mb-12">
           <div className="bg-gradient-to-r from-brand-900/40 to-dark-800 border border-brand-900/30 rounded-2xl p-8 flex flex-col md:flex-row items-center justify-between gap-6">
              <div>
                 <h1 className="text-3xl font-bold text-white mb-2">Sua Jornada de Leitura</h1>
                 <p className="text-gray-400 max-w-xl">
                    Bem-vindo à sua área de membros. Acesse seus e-books adquiridos ou assine o Clube para benefícios exclusivos.
                 </p>
              </div>
              <div className="w-full md:w-1/3">
                 <div className="bg-dark-900/50 p-4 rounded-xl border border-dark-700">
                    <div className="text-xs text-gray-500 uppercase font-bold mb-2">Status do Aluno</div>
