import React, { useState } from 'react';
import { FetishData, TargetAudience } from '../types';
import { Check, X, ArrowRight, ShieldCheck, Lock, CreditCard, ExternalLink } from 'lucide-react';

interface Props {
  fetish: FetishData;
  onClose: () => void;
  onUnlock: (fetishId: string, audience: TargetAudience) => void;
}

type Step = 'select_audience' | 'product_view' | 'checkout_bump';

const ProductFlow: React.FC<Props> = ({ fetish, onClose, onUnlock }) => {
  const [step, setStep] = useState<Step>('select_audience');
  const [audience, setAudience] = useState<TargetAudience>('Homens');
  const [hasBump, setHasBump] = useState(false);

  const product = fetish.products[audience];
  const basePrice = 47;
  const bumpPrice = product.bumpPrice;

  // Função para redirecionar para o Checkout da Ticto
  const handleRedirectToTicto = () => {
    // Escolhe a URL baseada na seleção do Order Bump
    // Se a Ticto permitir passar parâmetros na URL, você pode usar apenas uma URL base e adicionar ?bump=true
    // Aqui assumimos que você tem links diferentes ou configurou o bump no link
    const targetUrl = hasBump ? product.bundleUrl : product.checkoutUrl;

    // Abre em nova aba para não fechar o app completamente, 
    // mas o ideal em checkout é _self se quiser rastrear conversão melhor
    window.location.href = targetUrl;
  };

  const calculateTotal = () => {
    let total = basePrice;
    if (hasBump) total += bumpPrice;
    return total;
  };

  // --- RENDERS ---

  if (step === 'select_audience') {
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
        <div className="bg-dark-800 border border-brand-900 rounded-2xl w-full max-w-lg p-6 relative">
          <button onClick={onClose} className="absolute top-4 right-4 text-gray-500 hover:text-white"><X /></button>
          <h2 className="text-2xl font-bold text-white mb-2">{fetish.title}</h2>
          <p className="text-gray-400 mb-6">Para quem você quer comprar este guia?</p>

          <div className="space-y-3">
            {(['Homens', 'Mulheres', 'LGBT+'] as TargetAudience[]).map((aud) => (
              <button
                key={aud}
                onClick={() => { setAudience(aud); setStep('product_view'); }}
                className="w-full p-4 rounded-xl bg-dark-700 hover:bg-brand-900 border border-dark-600 hover:border-brand-500 transition-all flex justify-between items-center group text-left"
              >
                <div>
                  <span className="block font-bold text-white text-lg">{aud}</span>
                  <span className="text-xs text-gray-400 group-hover:text-brand-200">
                    {fetish.stats[aud === 'Homens' ? 'men' : aud === 'Mulheres' ? 'women' : 'lgbt']}
                  </span>
                </div>
                <ArrowRight className="text-dark-500 group-hover:text-brand-400" />
              </button>
            ))}
          </div>
        </div>
      </div>
    );
  }

  if (step === 'product_view') {
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 overflow-y-auto">
        <div className="bg-dark-800 border border-brand-900 rounded-2xl w-full max-w-2xl p-6 relative my-10">
          <button onClick={onClose} className="absolute top-4 right-4 text-gray-500 hover:text-white"><X /></button>

          <div className="mb-6">
            <span className="text-brand-400 text-xs font-bold tracking-widest uppercase">Guia Oficial • {audience}</span>
            <h2 className="text-3xl font-bold text-white mt-1 mb-2">{product.introTitle}</h2>
