/**
 * SQL PARA RODAR NO SUPABASE (QUERY EDITOR):
 * 
 * create table user_access (
 *   id uuid default uuid_generate_v4() primary key,
 *   user_email text not null,
 *   access_type text not null, -- 'course' ou 'subscription'
 *   item_id text not null, -- ex: 'anal', 'podolatria' ou 'club_membership'
 *   created_at timestamp with time zone default timezone('utc'::text, now())
 * );
 * 
 * -- Habilitar segurança (Row Level Security)
 * alter table user_access enable row level security;
 * 
 * -- Política: Usuário só vê seus próprios acessos
 * create policy "Users can view their own access"
 * on user_access for select
 * using ( auth.jwt() ->> 'email' = user_email );
 */

import { createClient } from '@supabase/supabase-js';

// Access import.meta.env safely to avoid crashes if it is undefined
const env = (import.meta as any).env || {};

// Tenta pegar as variáveis de ambiente (você vai configurar isso na Vercel depois)
const supabaseUrl = env.VITE_SUPABASE_URL;
const supabaseAnonKey = env.VITE_SUPABASE_ANON_KEY;

// Só cria o cliente se as chaves existirem, senão retorna null
export const supabase = (supabaseUrl && supabaseAnonKey) 
  ? createClient(supabaseUrl, supabaseAnonKey) 
  : null;

/**
 * SQL PARA RODAR NO SUPABASE (QUERY EDITOR):
 * 
 * create table user_access (
 *   id uuid default uuid_generate_v4() primary key,
 *   user_email text not null,
 *   access_type text not null, -- 'course' ou 'subscription'
 *   item_id text not null, -- ex: 'anal', 'podolatria' ou 'club_membership'
 *   created_at timestamp with time zone default timezone('utc'::text, now())
 * );
 * 
 * -- Habilitar segurança (Row Level Security)
 * alter table user_access enable row level security;
 * 
 * -- Política: Usuário só vê seus próprios acessos
 * create policy "Users can view their own access"
 * on user_access for select
 * using ( auth.jwt() ->> 'email' = user_email );
 */

import { useState, useEffect } from 'react';
import { supabase } from '../lib/supabase';

export function useContentAccess() {
  // Estado local (inicia com LocalStorage para ser rápido)
  const [unlockedIds, setUnlockedIds] = useState<string[]>(() => {
    try {
      const saved = localStorage.getItem('kinkmaster_unlocked');
      return saved ? JSON.parse(saved) : ['anal'];
    } catch { return ['anal']; }
  });

  const [isSubscribed, setIsSubscribed] = useState<boolean>(() => {
    try {
      return localStorage.getItem('kinkmaster_subscribed') === 'true';
    } catch { return false; }
  });

  const [userEmail, setUserEmail] = useState<string | null>(null);

  // 1. Salvar no LocalStorage sempre que mudar (Backup/Offline)
  useEffect(() => {
    localStorage.setItem('kinkmaster_unlocked', JSON.stringify(unlockedIds));
  }, [unlockedIds]);

  useEffect(() => {
    localStorage.setItem('kinkmaster_subscribed', String(isSubscribed));
  }, [isSubscribed]);

  // 2. Se tiver Supabase conectado, tentar buscar permissões reais
  useEffect(() => {
    if (!supabase) return;

    const fetchPermissions = async () => {
      const { data: { user } } = await supabase.auth.getUser();
      if (user && user.email) {
        setUserEmail(user.email);

        // Buscar acessos no banco
        const { data, error } = await supabase
          .from('user_access')
          .select('access_type, item_id')
          .eq('user_email', user.email);

        if (!error && data) {
          const dbUnlocked = data
            .filter(d => d.access_type === 'course')
            .map(d => d.item_id);

          const dbSubscribed = data.some(d => d.item_id === 'club_membership');

          // Merge (juntar) o que tem no local com o que tem no banco
          setUnlockedIds(prev => [...new Set([...prev, ...dbUnlocked])]);
          if (dbSubscribed) setIsSubscribed(true);
        }
      } else {
        setUserEmail(null);
      }
    };

    fetchPermissions();

    // Escutar mudanças de login
    const { data: authListener } = supabase.auth.onAuthStateChange(async (event, session) => {
      if (session?.user) {
         fetchPermissions();
      } else if (event === 'SIGNED_OUT') {
         setUserEmail(null);
         // Opcional: Limpar acessos locais ao sair? 
         // Geralmente mantemos para UX, mas num app estrito limparíamos:
         // setUnlockedIds(['anal']); 
         // setIsSubscribed(false);
      }
    });

    return () => {
      authListener.subscription.unsubscribe();
    };
  }, []);

  // Função unificada para liberar conteúdo
  const unlockContent = async (id: string, type: 'course' | 'sub') => {
    if (type === 'course') {
        setUnlockedIds(prev => {
            if (prev.includes(id)) return prev;
            return [...prev, id];
        });
    } else {
        setIsSubscribed(true);
    }

    // Se estiver logado e com Supabase, salva no banco também
    if (supabase && userEmail) {
        await supabase.from('user_access').insert({
            user_email: userEmail,
            access_type: type === 'course' ? 'course' : 'subscription',
            item_id: type === 'course' ? id : 'club_membership'
        });
    }
  };

  const signOut = async () => {
      if (supabase) {
          await supabase.auth.signOut();
          setUserEmail(null);
      }
  };

  return {
    unlockedIds,
    isSubscribed,
    unlockContent,
    userEmail,
    signOut
  };
}

import React, { useState } from 'react';
import { supabase } from '../lib/supabase';
