  return (
    <div className="min-h-screen bg-dark-900 text-gray-100 font-sans selection:bg-brand-900 selection:text-white">
      {/* Success Notification */}
      {showSuccessMessage && (
          <div className="fixed top-20 right-4 bg-green-600 text-white px-6 py-4 rounded-xl shadow-2xl z-50 animate-bounce">
              <span className="font-bold block mb-1">Sucesso!</span>
              {showSuccessMessage}
          </div>
      )}

      {/* Header */}
      <header className="border-b border-dark-800 bg-dark-900/95 backdrop-blur sticky top-0 z-40">
        <div className="container mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2 cursor-pointer" onClick={() => setView('dashboard')}>
            <Flame className="text-brand-500" />
            <span className="font-bold text-xl tracking-tight text-white">Kink<span className="text-brand-500">Master</span></span>
          </div>
          <nav className="hidden md:flex gap-6 text-sm text-gray-400">
            <button onClick={() => setView('dashboard')} className="hover:text-brand-400 transition-colors">Biblioteca</button>
            <button onClick={() => setShowSubscriptionModal(true)} className="hover:text-brand-400 transition-colors flex items-center gap-1">
                {isSubscribed && <Crown size={14} className="text-brand-400" />} Club
            </button>
            <span className="hover:text-brand-400 transition-colors cursor-pointer">Suporte</span>
          </nav>
          <div className="flex items-center gap-3">
             <div className="text-right hidden md:block">
               <div className="text-xs text-gray-400">
                   {userEmail ? 'Logado como' : 'Bem-vindo,'}
               </div>
               <div className="text-sm font-bold text-white flex items-center justify-end gap-1">
                 {userEmail ? userEmail.split('@')[0] : 'Visitante'} {isSubscribed && <Crown size={12} className="text-brand-500" />}
               </div>
             </div>

             <button 
                onClick={handleUserClick}
                className={`w-10 h-10 rounded-full border flex items-center justify-center transition-all ${
                    isSubscribed 
                    ? 'bg-brand-900 border-brand-500 text-brand-200 hover:bg-brand-800' 
                    : userEmail 
                        ? 'bg-blue-900 border-blue-500 text-blue-200 hover:bg-blue-800'
                        : 'bg-dark-800 border-dark-700 text-gray-400 hover:bg-dark-700 hover:text-white'
                }`}
                title={userEmail ? "Clique para Sair" : "Clique para Entrar"}
             >
                {userEmail ? <User size={20} /> : <User size={20} />}
