          </div>
        </div>
      </header>

      <main className="container mx-auto px-4 py-8 md:py-12">

        {/* Welcome Banner */}
        <section className="mb-12">
           <div className="bg-gradient-to-r from-brand-900/40 to-dark-800 border border-brand-900/30 rounded-2xl p-8 flex flex-col md:flex-row items-center justify-between gap-6 relative overflow-hidden">
              <div className="relative z-10">
