import { Flame, Lock, User, Crown, LogOut, UserPlus } from 'lucide-react';
import { useContentAccess } from './hooks/useContentAccess';

const App: React.FC = () => {
  // Use the new hook that handles both LocalStorage and Supabase logic
  const { unlockedIds, isSubscribed, unlockContent, userEmail, signOut } = useContentAccess();

  // Navigation State
  const [view, setView] = useState<'dashboard' | 'player'>('dashboard');
  const [selectedLockedFetish, setSelectedLockedFetish] = useState<FetishData | null>(null);
  const [currentCourse, setCurrentCourse] = useState<{fetish: FetishData, audience: TargetAudience} | null>(null);
  const [showSubscriptionModal, setShowSubscriptionModal] = useState(false);

  // Auth Modal State: controls visibility AND initial tab
  const [authModalState, setAuthModalState] = useState<{ isOpen: boolean; tab: 'login' | 'signup' }>({ 
      isOpen: false, 
      tab: 'login' 
  });

  const [showSuccessMessage, setShowSuccessMessage] = useState<string | null>(null);

  // Check URL query params for Ticto success callback AND Supabase Hash for Email Confirmation
  useEffect(() => {
    // 1. Check for Ticto success (Query Params)
    const params = new URLSearchParams(window.location.search);
    const status = params.get('status');
    const fid = params.get('fid'); // Fetish ID from URL
    const type = params.get('type'); // 'sub' or 'product'

    if (status === 'success') {
       if (type === 'sub') {
           unlockContent('club', 'sub');
           setShowSuccessMessage("Parabéns! Você agora é membro do Club.");
       } else if (fid) {
           unlockContent(fid, 'course');
           setShowSuccessMessage("Pagamento confirmado! Seu guia foi desbloqueado.");
       }
       // Clean URL
       window.history.replaceState({}, document.title, "/");
       setTimeout(() => setShowSuccessMessage(null), 5000);
    }

    // 2. Check for Supabase Auth Confirmation (Hash Params)
    // O Supabase retorna algo como: #access_token=...&type=signup
    const hash = window.location.hash;
    if (hash && hash.includes('type=signup')) {
        setShowSuccessMessage("E-mail confirmado com sucesso! Você está logado.");
        // Limpar a URL para ficar bonita
        window.history.replaceState({}, document.title, "/");
        setTimeout(() => setShowSuccessMessage(null), 5000);
    } else if (hash && hash.includes('type=recovery')) {
        setShowSuccessMessage("Senha redefinida. Crie uma nova senha agora.");
        // Aqui poderíamos abrir um modal de nova senha, mas por enquanto só avisa
        window.history.replaceState({}, document.title, "/");
        setTimeout(() => setShowSuccessMessage(null), 5000);
    }

  }, []); // Empty dependency array as unlockContent is stable

  const handleUnlock = (fetishId: string, audience: TargetAudience) => {
    // Manual unlock override (used by ProductFlow simulator if needed)
    unlockContent(fetishId, 'course');
    setSelectedLockedFetish(null);
  };

  const handleSelectUnlocked = (fetish: FetishData) => {
    setCurrentCourse({ fetish, audience: 'Homens' });
    setView('player');
  };

  const handleSubscribe = () => {
     setShowSubscriptionModal(false);
  };

  const handleUserClick = () => {
      if (userEmail) {
          const confirm = window.confirm("Deseja sair da sua conta?");
          if (confirm) signOut();
      } else {
          setAuthModalState({ isOpen: true, tab: 'login' });
      }
  };

  if (view === 'player' && currentCourse) {
    return (
      <CoursePlayer 
        fetish={currentCourse.fetish} 
        audience={currentCourse.audience}
        onBack={() => setView('dashboard')} 
      />
