                        <button 
                            onClick={() => setAuthModalState({ isOpen: true, tab: 'signup' })}
                            className="px-6 py-2 bg-brand-600 hover:bg-brand-500 text-white text-sm font-bold rounded-lg transition-colors flex items-center gap-2"
                        >
                            <UserPlus size={16} /> Criar Conta Grátis
                        </button>
                     </div>
                 )}
              </div>
              <div className="w-full md:w-1/3 relative z-10">
                 <div className="bg-dark-900/50 p-4 rounded-xl border border-dark-700 backdrop-blur-sm">
                    <div className="text-xs text-gray-500 uppercase font-bold mb-2">Status do Aluno</div>
                    <div className="flex items-center justify-between text-sm mb-1">
                       <span className="text-white flex items-center gap-1">
                         {isSubscribed ? 'Membro Club' : 'Iniciante'}
                         {isSubscribed && <Crown size={12} className="text-brand-500" />}
                       </span>
                       <span className="text-brand-400">{unlockedIds.length} Guias</span>
                    </div>
                    <div className="w-full bg-dark-700 h-2 rounded-full overflow-hidden">
                       <div className="bg-brand-500 transition-all duration-1000" style={{ width: `${(unlockedIds.length / 12) * 100}%` }}></div>
                    </div>
                 </div>
              </div>
           </div>
        </section>

        {/* Dashboard Grid */}
        <Dashboard 
          unlockedIds={unlockedIds}
          isSubscribed={isSubscribed}
          onSelectLocked={setSelectedLockedFetish}
          onSelectUnlocked={handleSelectUnlocked}
          onOpenSubscribe={() => setShowSubscriptionModal(true)}
        />

        <div className="mt-16 mb-8">
           <TrendChart />
        </div>

        {/* Footer info */}
        <section className="mt-20 border-t border-dark-800 pt-10 text-center text-gray-500 text-sm">
          <div className="max-w-2xl mx-auto space-y-4">
             <div className="flex justify-center gap-4 mb-4">
