import React, { useState, useEffect, useRef } from 'react';
import { Send, Lock, Crown, User, MoreVertical } from 'lucide-react';
import { supabase } from '../lib/supabase';

interface Props {
  isSubscribed: boolean;
  userEmail: string | null;
  onOpenSubscribe: () => void;
}

interface Message {
  id: string;
  user_email: string;
  content: string;
  created_at: string;
}

const ClubChat: React.FC<Props> = ({ isSubscribed, userEmail, onOpenSubscribe }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [newMessage, setNewMessage] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  // Auto-scroll
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  // Carregar Mensagens e Realtime
  useEffect(() => {
    if (!isSubscribed || !supabase) return;

    // 1. Carregar mensagens iniciais
    const fetchMessages = async () => {
      const { data, error } = await supabase
        .from('chat_messages')
        .select('*')
        .order('created_at', { ascending: true })
        .limit(50);

      if (!error && data) {
        setMessages(data);
      }
    };

    fetchMessages();

    // 2. Inscrever no Realtime
    const channel = supabase
      .channel('public:chat_messages')
      .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'chat_messages' }, (payload) => {
        const newMsg = payload.new as Message;
        setMessages((prev) => [...prev, newMsg]);
      })
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [isSubscribed]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newMessage.trim() || !userEmail || !supabase) return;

    const text = newMessage;
    setNewMessage(''); // Otimista

    const { error } = await supabase
      .from('chat_messages')
      .insert({
        user_email: userEmail,
        content: text
      });

    if (error) {
      console.error('Erro ao enviar:', error);
      setNewMessage(text); // Devolve o texto se falhar
    }
  };

  // Render para NÃO assinantes (Bloqueado)
  if (!isSubscribed) {
    return (
      <div className="relative h-[calc(100vh-140px)] md:h-[600px] bg-dark-800 rounded-2xl overflow-hidden border border-dark-700 flex flex-col items-center justify-center p-6 text-center">
        {/* Fake Background Blur */}
        <div className="absolute inset-0 p-6 space-y-4 opacity-10 filter blur-sm pointer-events-none select-none">
           <div className="flex gap-3"><div className="w-8 h-8 rounded-full bg-gray-500"></div><div className="bg-dark-700 rounded-lg p-3 w-2/3"></div></div>
           <div className="flex gap-3 flex-row-reverse"><div className="w-8 h-8 rounded-full bg-brand-500"></div><div className="bg-brand-900 rounded-lg p-3 w-2/3"></div></div>
           <div className="flex gap-3"><div className="w-8 h-8 rounded-full bg-gray-500"></div><div className="bg-dark-700 rounded-lg p-3 w-1/2"></div></div>
        </div>

        <div className="relative z-10 bg-dark-900/90 p-8 rounded-2xl border border-brand-500/30 shadow-2xl max-w-sm">
           <div className="w-16 h-16 bg-brand-900/30 rounded-full flex items-center justify-center mx-auto mb-4 border border-brand-500/50">
              <Lock size={32} className="text-brand-400" />
           </div>
           <h2 className="text-xl font-bold text-white mb-2">Comunidade Exclusiva</h2>
           <p className="text-gray-400 text-sm mb-6">
             O chat é reservado para membros do KinkMaster Club trocarem experiências e dúvidas em segurança.
           </p>
           <button 
             onClick={onOpenSubscribe}
             className="w-full py-3 bg-brand-600 hover:bg-brand-500 text-white rounded-xl font-bold transition-all flex justify-center items-center gap-2"
           >
              <Crown size={18} /> Liberar Acesso VIP
           </button>
        </div>
      </div>
    );
  }

  // Render para Assinantes
  return (
    <div className="h-[calc(100vh-140px)] md:h-[600px] bg-dark-800 rounded-2xl overflow-hidden border border-dark-700 flex flex-col">
       {/* Header */}
       <div className="bg-dark-900 border-b border-dark-700 p-4 flex items-center justify-between">
          <div className="flex items-center gap-3">
             <div className="relative">
                <div className="w-10 h-10 bg-gradient-to-tr from-brand-600 to-purple-600 rounded-full flex items-center justify-center">
                   <MessageCircle size={20} className="text-white" />
                </div>
                <div className="absolute bottom-0 right-0 w-3 h-3 bg-green-500 rounded-full border-2 border-dark-900"></div>
             </div>
             <div>
                <h3 className="font-bold text-white">Lounge do Club</h3>
                <p className="text-xs text-brand-400 font-medium">Chat Oficial da Comunidade</p>
             </div>
          </div>
          <button className="text-gray-500 hover:text-white">
             <MoreVertical size={20} />
          </button>
       </div>

       {/* Messages Area */}
       <div 
          ref={scrollRef}
          className="flex-1 overflow-y-auto p-4 space-y-4 bg-dark-800"
       >
          <div className="text-center text-xs text-gray-600 my-4">
             --- Início da conversa ---
          </div>

          {messages.map((msg) => {
             const isMe = userEmail === msg.user_email;
             const nickname = msg.user_email.split('@')[0];

             return (
               <div key={msg.id} className={`flex gap-3 ${isMe ? 'flex-row-reverse' : ''}`}>
                  <div className={`w-8 h-8 rounded-full shrink-0 flex items-center justify-center ${isMe ? 'bg-brand-900 text-brand-200' : 'bg-dark-700 text-gray-400'}`}>
                     <User size={14} />
                  </div>
                  <div className={`max-w-[75%] ${isMe ? 'items-end' : 'items-start'} flex flex-col`}>
                     <div className="flex items-center gap-2 mb-1">
                        <span className="text-[10px] font-bold text-gray-500">{nickname}</span>
                     </div>
                     <div className={`p-3 rounded-2xl text-sm ${isMe ? 'bg-brand-600 text-white rounded-tr-none' : 'bg-dark-700 text-gray-200 rounded-tl-none'}`}>
                        {msg.content}
                     </div>
                  </div>
               </div>
             );
          })}
       </div>

