import React, { useState, useEffect, useRef } from 'react';
import { Send, Lock, Crown, User, MoreVertical, MessageCircle } from 'lucide-react';
import { supabase } from '../lib/supabase';

interface Props {
  isSubscribed: boolean;
  userEmail: string | null;
  onOpenSubscribe: () => void;
}

interface Message {
  id: string;
  user_email: string;
  content: string;
  created_at: string;
}

const ClubChat: React.FC<Props> = ({ isSubscribed, userEmail, onOpenSubscribe }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [newMessage, setNewMessage] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  // Auto-scroll
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  // Carregar Mensagens e Realtime
  useEffect(() => {
    if (!isSubscribed || !supabase) return;

    // 1. Carregar mensagens iniciais
    const fetchMessages = async () => {
      if (!supabase) return;

      const { data, error } = await supabase
        .from('chat_messages')
        .select('*')
        .order('created_at', { ascending: true })
        .limit(50);

      if (!error && data) {
        setMessages(data as any[]);
      }
    };

    fetchMessages();

    // 2. Inscrever no Realtime
    const channel = supabase
      .channel('public:chat_messages')
      .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'chat_messages' }, (payload) => {
        const newMsg = payload.new as Message;
        setMessages((prev) => [...prev, newMsg]);
      })
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [isSubscribed]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newMessage.trim() || !userEmail || !supabase) return;

    const text = newMessage;
    setNewMessage(''); // Otimista

    const { error } = await supabase
      .from('chat_messages')
      .insert({
        user_email: userEmail,
        content: text
      });

    if (error) {
      console.error('Erro ao enviar:', error);
      setNewMessage(text); // Devolve o texto se falhar
    }
  };

  // Render para NÃO assinantes (Bloqueado)
  if (!isSubscribed) {
    return (
      <div className="relative h-[calc(100vh-140px)] md:h-[600px] bg-dark-800 rounded-2xl overflow-hidden border border-dark-700 flex flex-col items-center justify-center p-6 text-center">
