                        <span className="text-[10px] font-bold text-gray-500">{nickname}</span>
                     </div>
                     <div className={`p-3 rounded-2xl text-sm ${isMe ? 'bg-brand-600 text-white rounded-tr-none' : 'bg-dark-700 text-gray-200 rounded-tl-none'}`}>
                        {msg.content}
