import { createClient } from '@supabase/supabase-js';

// Access import.meta.env safely to avoid crashes if it is undefined
const env = (import.meta as any).env || {};

// Tenta pegar as variáveis de ambiente (você vai configurar isso na Vercel depois)
const supabaseUrl = env.VITE_SUPABASE_URL;
const supabaseAnonKey = env.VITE_SUPABASE_ANON_KEY;

// Só cria o cliente se as chaves existirem, senão retorna null
export const supabase = (supabaseUrl && supabaseAnonKey) 
  ? createClient(supabaseUrl, supabaseAnonKey) 
  : null;

/**
 * ==========================================
 * GUIA DE CONFIGURAÇÃO DO BANCO DE DADOS (SQL)
 * ==========================================
 * Vá até o painel do Supabase > SQL Editor e cole o código abaixo para configurar tudo.
 * 
 * --- 1. TABELA DE PERMISSÕES (Quem comprou o quê) ---
 * 
 * create table user_access (
 *   id uuid default uuid_generate_v4() primary key,
 *   user_email text not null,
 *   access_type text not null, -- 'course' (para cursos avulsos) ou 'subscription' (para o Club)
 *   item_id text not null, -- ID do produto (ex: 'anal', 'podolatria') ou 'club_membership'
 *   created_at timestamp with time zone default timezone('utc'::text, now())
 * );
 * 
 * -- Segurança: Usuário só vê seus próprios acessos
 * alter table user_access enable row level security;
 * create policy "Users can view their own access" on user_access for select using ( auth.jwt() ->> 'email' = user_email );
 * 
 * 
 * --- 2. TABELA DO CHAT (Para o Club) ---
 * 
 * create table chat_messages (
 *   id uuid default uuid_generate_v4() primary key,
 *   user_email text not null,
 *   content text not null,
 *   created_at timestamp with time zone default timezone('utc'::text, now())
 * );
 * 
 * -- Habilitar Realtime (Para as mensagens aparecerem na hora)
 * alter publication supabase_realtime add table chat_messages;
 * 
 * -- Segurança: Apenas usuários logados podem ler e escrever
 * alter table chat_messages enable row level security;
 * create policy "Authenticated users can read messages" on chat_messages for select to authenticated using (true);
 * create policy "Authenticated users can insert messages" on chat_messages for insert to authenticated with check (auth.jwt() ->> 'email' = user_email);
 */

import React, { useState } from 'react';
import { supabase } from '../lib/supabase';
import { FETISH_DATA } from '../constants';
import { ShieldAlert, Save, Trash2, Search, CheckCircle, XCircle } from 'lucide-react';

