        .eq('item_id', accessType === 'subscription' ? 'club_membership' : itemId)
        .single();

      if (existing) {
        throw new Error("Este usuário já possui este acesso.");
      }

      // 2. Inserir
      const { error } = await supabase
        .from('user_access')
        .insert({
          user_email: targetEmail,
          access_type: accessType,
          item_id: accessType === 'subscription' ? 'club_membership' : itemId
        });

      if (error) throw error;

      setMessage({ type: 'success', text: `Acesso liberado para ${targetEmail}!` });
      setTargetEmail(''); // Limpar campo para próxima inserção

    } catch (err: any) {
      setMessage({ type: 'error', text: err.message });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-2xl mx-auto mt-8">
      <div className="bg-dark-800 border border-red-900/50 rounded-2xl p-6 shadow-2xl relative overflow-hidden">
        {/* Header Admin */}
        <div className="flex items-center gap-3 mb-6 border-b border-dark-700 pb-4">
          <div className="bg-red-900/20 p-3 rounded-full">
            <ShieldAlert className="text-red-500" size={24} />
          </div>
          <div>
            <h2 className="text-xl font-bold text-white">Painel Administrativo</h2>
            <p className="text-xs text-gray-500">Acesso restrito. Use com cautela.</p>
          </div>
        </div>

        {/* Feedback Message */}
        {message && (
          <div className={`p-4 rounded-xl mb-6 flex items-center gap-3 ${message.type === 'success' ? 'bg-green-900/20 text-green-400 border border-green-900' : 'bg-red-900/20 text-red-400 border border-red-900'}`}>
            {message.type === 'success' ? <CheckCircle size={20} /> : <XCircle size={20} />}
            <span className="text-sm font-semibold">{message.text}</span>
          </div>
        )}

        {/* Form */}
        <form onSubmit={handleGrantAccess} className="space-y-6">

          {/* Email do Usuário */}
          <div>
            <label className="block text-xs font-bold text-gray-500 uppercase mb-1">E-mail do Cliente</label>
            <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-600" size={18} />
                <input 
                  type="email" 
                  required
                  value={targetEmail}
                  onChange={(e) => setTargetEmail(e.target.value)}
                  placeholder="cliente@exemplo.com"
                  className="w-full bg-dark-900 border border-dark-600 rounded-xl py-3 pl-10 pr-4 text-white focus:border-red-500 focus:outline-none transition-colors"
                />
            </div>
          </div>

          {/* Tipo de Acesso */}
          <div className="grid grid-cols-2 gap-4">
            <button
              type="button"
              onClick={() => setAccessType('subscription')}
              className={`p-4 rounded-xl border flex flex-col items-center gap-2 transition-all ${accessType === 'subscription' ? 'bg-red-900/20 border-red-500 text-white' : 'bg-dark-900 border-dark-600 text-gray-500 hover:border-gray-500'}`}
            >
              <span className="font-bold">Liberar Club</span>
              <span className="text-[10px] uppercase">Assinatura</span>
            </button>

            <button
              type="button"
              onClick={() => setAccessType('course')}
              className={`p-4 rounded-xl border flex flex-col items-center gap-2 transition-all ${accessType === 'course' ? 'bg-brand-900/20 border-brand-500 text-white' : 'bg-dark-900 border-dark-600 text-gray-500 hover:border-gray-500'}`}
            >
              <span className="font-bold">Liberar Guia</span>
              <span className="text-[10px] uppercase">Curso Avulso</span>
            </button>
          </div>

          {/* Seletor de Curso (Só aparece se for 'course') */}
          {accessType === 'course' && (
             <div className="animate-in fade-in slide-in-from-top-2">
                <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Selecione o Guia</label>
                <select 
                  value={itemId}
                  onChange={(e) => setItemId(e.target.value)}
                  className="w-full bg-dark-900 border border-dark-600 rounded-xl py-3 px-4 text-white focus:border-brand-500 focus:outline-none"
                >
                  {FETISH_DATA.map(f => (
                    <option key={f.id} value={f.id}>{f.title}</option>
                  ))}
                </select>
             </div>
          )}

          <div className="pt-4 border-t border-dark-700">
             <button 
               type="submit" 
               disabled={loading || !targetEmail}
               className="w-full bg-white text-dark-900 font-bold py-3 rounded-xl hover:bg-gray-200 transition-colors flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
             >
               {loading ? 'Processando...' : <><Save size={18} /> Conceder Acesso Manualmente</>}
             </button>
          </div>

        </form>
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState, useEffect } from 'react';
import { FETISH_DATA } from './constants';
import { FetishData, TargetAudience } from './types';
import TrendChart from './components/TrendChart';
import ProductFlow from './components/ProductFlow';
import Dashboard from './components/Dashboard';
import CoursePlayer from './components/CoursePlayer';
import SubscriptionModal from './components/SubscriptionModal';
import AuthModal from './components/AuthModal';
import Profile from './components/Profile';
import ClubChat from './components/ClubChat';
import AdminPanel, { CONST_ADMIN_EMAIL } from './components/AdminPanel'; // Import Admin
import { Flame, Lock, User, Crown, UserPlus, Home, MessageCircle, ShieldAlert } from 'lucide-react';
import { useContentAccess } from './hooks/useContentAccess';

const App: React.FC = () => {
  // Use the new hook that handles both LocalStorage and Supabase logic
  const { unlockedIds, isSubscribed, unlockContent, userEmail, signOut } = useContentAccess();

  // Navigation State - Adicionado 'admin' ao tipo
  const [view, setView] = useState<'dashboard' | 'player' | 'profile' | 'chat' | 'admin'>('dashboard');
  const [selectedLockedFetish, setSelectedLockedFetish] = useState<FetishData | null>(null);
  const [currentCourse, setCurrentCourse] = useState<{fetish: FetishData, audience: TargetAudience} | null>(null);
  const [showSubscriptionModal, setShowSubscriptionModal] = useState(false);

  // Auth Modal State
  const [authModalState, setAuthModalState] = useState<{ isOpen: boolean; tab: 'login' | 'signup' }>({ 
      isOpen: false, 
      tab: 'login' 
  });

  const [showSuccessMessage, setShowSuccessMessage] = useState<string | null>(null);

  // Check URL query params...
  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const status = params.get('status');
    const fid = params.get('fid');
    const type = params.get('type');

    if (status === 'success') {
       if (type === 'sub') {
           unlockContent('club', 'sub');
           setShowSuccessMessage("Parabéns! Você agora é membro do Club.");
       } else if (fid) {
           unlockContent(fid, 'course');
           setShowSuccessMessage("Pagamento confirmado! Seu guia foi desbloqueado.");
       }
       window.history.replaceState({}, document.title, "/");
       setTimeout(() => setShowSuccessMessage(null), 5000);
    }

    const hash = window.location.hash;
    if (hash && hash.includes('type=signup')) {
        setShowSuccessMessage("E-mail confirmado com sucesso! Você está logado.");
        window.history.replaceState({}, document.title, "/");
        setTimeout(() => setShowSuccessMessage(null), 5000);
    } else if (hash && hash.includes('type=recovery')) {
        setShowSuccessMessage("Senha redefinida. Crie uma nova senha agora.");
        window.history.replaceState({}, document.title, "/");
        setTimeout(() => setShowSuccessMessage(null), 5000);
    }

  }, []);

  const handleUnlock = (fetishId: string, audience: TargetAudience) => {
    unlockContent(fetishId, 'course');
    setSelectedLockedFetish(null);
  };

  const handleSelectUnlocked = (fetish: FetishData) => {
    setCurrentCourse({ fetish, audience: 'Homens' });
    setView('player');
  };

  const handleSubscribe = () => {
     setShowSubscriptionModal(false);
  };

  const handleUserClick = () => {
      if (userEmail) {
          setView('profile');
      } else {
          setAuthModalState({ isOpen: true, tab: 'login' });
      }
  };

  const handleLogout = () => {
      const confirm = window.confirm("Deseja realmente sair?");
      if (confirm) {
          signOut();
          setView('dashboard');
      }
  };

  // Verifica se é admin
  const isAdmin = userEmail === CONST_ADMIN_EMAIL;

  if (view === 'player' && currentCourse) {
    return (
      <CoursePlayer 
        fetish={currentCourse.fetish} 
        audience={currentCourse.audience}
        onBack={() => setView('dashboard')} 
      />
    );
  }

  return (
    <div className="min-h-screen bg-dark-900 text-gray-100 font-sans selection:bg-brand-900 selection:text-white pb-20 md:pb-0">
      {/* Success Notification */}
      {showSuccessMessage && (
          <div className="fixed top-20 right-4 bg-green-600 text-white px-6 py-4 rounded-xl shadow-2xl z-50 animate-bounce">
              <span className="font-bold block mb-1">Sucesso!</span>
              {showSuccessMessage}
          </div>
      )}

      {/* Header (Desktop & Mobile Top) */}
      <header className="border-b border-dark-800 bg-dark-900/95 backdrop-blur sticky top-0 z-40">
        <div className="container mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2 cursor-pointer" onClick={() => setView('dashboard')}>
            <Flame className="text-brand-500" />
            <span className="font-bold text-xl tracking-tight text-white">Kink<span className="text-brand-500">Master</span></span>
          </div>

          {/* Desktop Nav */}
          <nav className="hidden md:flex gap-6 text-sm text-gray-400">
            <button onClick={() => setView('dashboard')} className={`hover:text-brand-400 transition-colors ${view === 'dashboard' ? 'text-white font-bold' : ''}`}>Biblioteca</button>
            <button onClick={() => setView('chat')} className={`hover:text-brand-400 transition-colors flex items-center gap-1 ${view === 'chat' ? 'text-white font-bold' : ''}`}>
               Chat Club {isSubscribed && <Lock size={12} className="text-brand-500" />}
            </button>
            <button onClick={() => setShowSubscriptionModal(true)} className="hover:text-brand-400 transition-colors flex items-center gap-1">
                {isSubscribed && <Crown size={14} className="text-brand-400" />} Assinatura
            </button>

            {/* ADMIN LINK - Só aparece se for o admin */}
            {isAdmin && (
                <button onClick={() => setView('admin')} className={`hover:text-red-400 transition-colors flex items-center gap-1 ${view === 'admin' ? 'text-red-500 font-bold' : 'text-red-500/70'}`}>
                    <ShieldAlert size={14} /> Admin
                </button>
            )}
          </nav>

          {/* User Status (Desktop) */}
          <div className="hidden md:flex items-center gap-3">
             <div className="text-right">
               <div className="text-xs text-gray-400">
                   {userEmail ? 'Logado como' : 'Bem-vindo,'}
               </div>
               <div className="text-sm font-bold text-white flex items-center justify-end gap-1">
                 {userEmail ? userEmail.split('@')[0] : 'Visitante'} 
                 {isSubscribed && <Crown size={12} className="text-brand-500" />}
                 {isAdmin && <ShieldAlert size={12} className="text-red-500" />}
               </div>
             </div>

             <button 
                onClick={handleUserClick}
                className={`w-10 h-10 rounded-full border flex items-center justify-center transition-all ${
                    isAdmin
                    ? 'bg-red-900 border-red-500 text-white'
                    : isSubscribed 
                    ? 'bg-brand-900 border-brand-500 text-brand-200 hover:bg-brand-800' 
                    : userEmail 
                        ? 'bg-blue-900 border-blue-500 text-blue-200 hover:bg-blue-800'
                        : 'bg-dark-800 border-dark-700 text-gray-400 hover:bg-dark-700 hover:text-white'
                }`}
                title="Meu Perfil"
             >
                <User size={20} />
             </button>
          </div>

          {/* Mobile Club Button */}
          <div className="md:hidden">
             <button onClick={() => setShowSubscriptionModal(true)} className="text-brand-500 font-bold text-sm flex items-center gap-1">
                Club <Crown size={16} />
             </button>
          </div>
        </div>
      </header>

      <main className="container mx-auto px-4 py-8 md:py-12">
        {view === 'dashboard' ? (
            <>
                {/* Welcome Banner */}
                <section className="mb-12">
                <div className="bg-gradient-to-r from-brand-900/40 to-dark-800 border border-brand-900/30 rounded-2xl p-8 flex flex-col md:flex-row items-center justify-between gap-6 relative overflow-hidden">
                    <div className="relative z-10">
                        <h1 className="text-3xl font-bold text-white mb-2">Sua Jornada de Leitura</h1>
                        <p className="text-gray-400 max-w-xl">
                            {userEmail 
                                ? "Bem-vindo de volta! Seus guias estão sincronizados na nuvem." 
                                : "Entre na sua conta para salvar seu progresso e acessar seus guias em qualquer dispositivo."}
                        </p>
                        {!userEmail && (
                            <div className="flex gap-3 mt-4">
                                <button 
                                    onClick={() => setAuthModalState({ isOpen: true, tab: 'login' })}
                                    className="px-6 py-2 bg-dark-700 hover:bg-brand-900 text-white text-sm font-bold rounded-lg border border-dark-600 transition-colors"
                                >
                                    Entrar
                                </button>
                                <button 
                                    onClick={() => setAuthModalState({ isOpen: true, tab: 'signup' })}
                                    className="px-6 py-2 bg-brand-600 hover:bg-brand-500 text-white text-sm font-bold rounded-lg transition-colors flex items-center gap-2"
                                >
                                    <UserPlus size={16} /> Criar Conta Grátis
                                </button>
                            </div>
                        )}
                    </div>
                    <div className="w-full md:w-1/3 relative z-10 hidden md:block">
                        <div className="bg-dark-900/50 p-4 rounded-xl border border-dark-700 backdrop-blur-sm">
                            <div className="text-xs text-gray-500 uppercase font-bold mb-2">Status do Aluno</div>
                            <div className="flex items-center justify-between text-sm mb-1">
                            <span className="text-white flex items-center gap-1">
                                {isSubscribed ? 'Membro Club' : 'Iniciante'}
                                {isSubscribed && <Crown size={12} className="text-brand-500" />}
                            </span>
                            <span className="text-brand-400">{unlockedIds.length} Guias</span>
                            </div>
                            <div className="w-full bg-dark-700 h-2 rounded-full overflow-hidden">
                            <div className="bg-brand-500 transition-all duration-1000" style={{ width: `${(unlockedIds.length / 12) * 100}%` }}></div>
                            </div>
                        </div>
                    </div>
                </div>
                </section>

                <Dashboard 
                    unlockedIds={unlockedIds}
                    isSubscribed={isSubscribed}
                    onSelectLocked={setSelectedLockedFetish}
                    onSelectUnlocked={handleSelectUnlocked}
                    onOpenSubscribe={() => setShowSubscriptionModal(true)}
                />

                <div className="mt-16 mb-8">
                   <TrendChart />
                </div>
            </>
        ) : view === 'profile' ? (
            <Profile 
                userEmail={userEmail || 'Convidado'}
                isSubscribed={isSubscribed}
                unlockedIds={unlockedIds}
                onLogout={handleLogout}
                onRead={(id) => {
                    const fetish = FETISH_DATA.find(f => f.id === id);
                    if(fetish) handleSelectUnlocked(fetish);
                }}
                onOpenSubscribe={() => setShowSubscriptionModal(true)}
            />
        ) : view === 'chat' ? (
            <ClubChat 
                isSubscribed={isSubscribed}
                userEmail={userEmail}
                onOpenSubscribe={() => setShowSubscriptionModal(true)}
            />
        ) : view === 'admin' && isAdmin ? (
            <AdminPanel />
        ) : null}

        {/* Footer info */}
        <section className="mt-20 border-t border-dark-800 pt-10 text-center text-gray-500 text-sm pb-10 md:pb-0">
          <div className="max-w-2xl mx-auto space-y-4">
             <div className="flex justify-center gap-4 mb-4">
                <Lock size={16} />
                <span>Ambiente Seguro e Discreto</span>
             </div>
             <p>© 2026 KinkMaster Brasil. Todos os direitos reservados.</p>
          </div>
        </section>
      </main>

      {/* Mobile Bottom Navigation (Fixed) */}
      <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-dark-900 border-t border-dark-800 flex justify-around p-3 z-50 pb-safe">
        {isAdmin && (
             <button 
                onClick={() => setView('admin')}
                className={`flex flex-col items-center gap-1 text-xs ${view === 'admin' ? 'text-red-500 font-bold' : 'text-gray-500'}`}
            >
                <ShieldAlert size={22} className={view === 'admin' ? "fill-red-500/20" : ""} />
                <span>Admin</span>
            </button>
        )}
        <button 
            onClick={() => setView('dashboard')}
            className={`flex flex-col items-center gap-1 text-xs ${view === 'dashboard' ? 'text-brand-500 font-bold' : 'text-gray-500'}`}
        >
            <Home size={22} />
            <span>Início</span>
        </button>
        <button 
            onClick={() => setView('chat')}
            className={`flex flex-col items-center gap-1 text-xs ${view === 'chat' ? 'text-brand-500 font-bold' : 'text-gray-500'}`}
        >
            <MessageCircle size={22} className={isSubscribed ? "text-brand-500" : ""} />
            <span>Chat</span>
        </button>
        <button 
            onClick={() => setShowSubscriptionModal(true)}
            className={`flex flex-col items-center gap-1 text-xs ${showSubscriptionModal ? 'text-brand-500 font-bold' : 'text-gray-500'}`}
        >
            <Crown size={22} className={isSubscribed ? "text-brand-500 fill-brand-500" : ""} />
            <span>Club</span>
        </button>
        <button 
            onClick={handleUserClick}
            className={`flex flex-col items-center gap-1 text-xs ${view === 'profile' ? 'text-brand-500 font-bold' : 'text-gray-500'}`}
        >
            <User size={22} />
            <span>Perfil</span>
        </button>
      </nav>

      {/* Modals */}
      {selectedLockedFetish && (
        <ProductFlow 
          fetish={selectedLockedFetish} 
          onClose={() => setSelectedLockedFetish(null)} 
          onUnlock={handleUnlock}
        />
      )}

      {showSubscriptionModal && (
        <SubscriptionModal 
            onClose={() => setShowSubscriptionModal(false)}
            onSubscribe={handleSubscribe}
        />
      )}

      {authModalState.isOpen && (
          <AuthModal 
            initialTab={authModalState.tab}
            onClose={() => setAuthModalState({ ...authModalState, isOpen: false })} 
          />
      )}
    </div>
  );
};

export default App;

