                         <span className="text-xs font-bold text-gray-400">{displayName.charAt(0).toUpperCase()}</span>
                     )}
                  </div>
                  <div className={`max-w-[75%] ${isMe ? 'items-end' : 'items-start'} flex flex-col`}>
                     <div className="flex items-center gap-2 mb-1">
                        <span className="text-[10px] font-bold text-gray-500">{displayName}</span>
                     </div>
                     <div className={`p-3 rounded-2xl text-sm ${isMe ? 'bg-brand-600 text-white rounded-tr-none' : 'bg-dark-700 text-gray-200 rounded-tl-none'}`}>
                        {msg.content}
                     </div>
                  </div>
               </div>
             );
          })}
       </div>

       {/* Input Area */}
       <form onSubmit={handleSend} className="bg-dark-900 p-4 border-t border-dark-700 flex gap-3">
          <input 
             type="text" 
             value={newMessage}
             onChange={(e) => setNewMessage(e.target.value)}
             placeholder="Digite sua mensagem..."
             className="flex-1 bg-dark-800 text-white border border-dark-600 rounded-xl px-4 py-3 focus:outline-none focus:border-brand-500 placeholder:text-gray-600 text-sm"
          />
          <button 
             type="submit" 
             disabled={!newMessage.trim()}
             className="bg-brand-600 hover:bg-brand-500 disabled:opacity-50 disabled:cursor-not-allowed text-white p-3 rounded-xl transition-colors"
          >
             <Send size={20} />
          </button>
       </form>
    </div>
  );
};

export default ClubChat;

import React, { useState, useEffect } from 'react';
import { supabase } from './lib/supabase';
import { FETISH_DATA } from './constants';
import { FetishData, TargetAudience } from './types';
import TrendChart from './components/TrendChart';
import ProductFlow from './components/ProductFlow';
import Dashboard from './components/Dashboard';
import CoursePlayer from './components/CoursePlayer';
import SubscriptionModal from './components/SubscriptionModal';
import AuthModal from './components/AuthModal';
import Profile from './components/Profile';
import ClubChat from './components/ClubChat';
import AdminPanel, { CONST_ADMIN_EMAIL } from './components/AdminPanel'; 
import CompleteRegistration from './components/CompleteRegistration'; // Novo Import
import { Flame, Lock, User, Crown, UserPlus, Home, MessageCircle, ShieldAlert } from 'lucide-react';
import { useContentAccess } from './hooks/useContentAccess';

const App: React.FC = () => {
  const { unlockedIds, isSubscribed, unlockContent, userEmail, signOut } = useContentAccess();

  const [view, setView] = useState<'dashboard' | 'player' | 'profile' | 'chat' | 'admin'>('dashboard');
  const [selectedLockedFetish, setSelectedLockedFetish] = useState<FetishData | null>(null);
  const [currentCourse, setCurrentCourse] = useState<{fetish: FetishData, audience: TargetAudience} | null>(null);
  const [showSubscriptionModal, setShowSubscriptionModal] = useState(false);

  // Auth & Profile State
  const [authModalState, setAuthModalState] = useState<{ isOpen: boolean; tab: 'login' | 'signup' }>({ 
      isOpen: false, 
      tab: 'login' 
  });
  const [showCompleteRegistration, setShowCompleteRegistration] = useState(false);
  const [isProfileComplete, setIsProfileComplete] = useState(false);

  const [showSuccessMessage, setShowSuccessMessage] = useState<string | null>(null);

  // Check Profile Completion on Login
  useEffect(() => {
    if (userEmail && supabase) {
        const checkProfile = async () => {
            const { data } = await supabase.from('profiles').select('full_name').eq('email', userEmail).single();
            if (data && data.full_name) {
                setIsProfileComplete(true);
            } else {
                setIsProfileComplete(false);
                // Se o usuário tentar acessar chat ou perfil e não estiver completo, forçamos
                if (view === 'chat' || view === 'profile') {
                    setShowCompleteRegistration(true);
                }
            }
        };
        checkProfile();
    }
  }, [userEmail, view]);

  // Check URL query params...
  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const status = params.get('status');
    const fid = params.get('fid');
    const type = params.get('type');

    if (status === 'success') {
       if (type === 'sub') {
           unlockContent('club', 'sub');
           setShowSuccessMessage("Parabéns! Você agora é membro do Club.");
       } else if (fid) {
           unlockContent(fid, 'course');
           setShowSuccessMessage("Pagamento confirmado! Seu guia foi desbloqueado.");
       }
       window.history.replaceState({}, document.title, "/");
       setTimeout(() => setShowSuccessMessage(null), 5000);
    }

    const hash = window.location.hash;
    if (hash && hash.includes('type=signup')) {
        setShowSuccessMessage("E-mail confirmado com sucesso! Você está logado.");
        window.history.replaceState({}, document.title, "/");
        setTimeout(() => setShowSuccessMessage(null), 5000);
    }
  }, []);

  const handleUnlock = (fetishId: string, audience: TargetAudience) => {
    unlockContent(fetishId, 'course');
    setSelectedLockedFetish(null);
  };

  const handleSelectUnlocked = (fetish: FetishData) => {
    setCurrentCourse({ fetish, audience: 'Homens' });
    setView('player');
  };

  const handleSubscribe = () => {
     setShowSubscriptionModal(false);
  };

  const handleUserClick = () => {
      if (userEmail) {
          if(!isProfileComplete) setShowCompleteRegistration(true);
          setView('profile');
      } else {
          setAuthModalState({ isOpen: true, tab: 'login' });
      }
  };

  const handleChatClick = () => {
      if(!userEmail) {
         setAuthModalState({ isOpen: true, tab: 'login' });
      } else if (!isProfileComplete) {
         setShowCompleteRegistration(true);
      } else {
         setView('chat');
      }
  }

  const handleLogout = () => {
      const confirm = window.confirm("Deseja realmente sair?");
      if (confirm) {
          signOut();
          setView('dashboard');
      }
  };

  const isAdmin = userEmail === CONST_ADMIN_EMAIL;

  if (view === 'player' && currentCourse) {
    return (
      <CoursePlayer 
        fetish={currentCourse.fetish} 
        audience={currentCourse.audience}
        onBack={() => setView('dashboard')} 
      />
    );
  }

  return (
    <div className="min-h-screen bg-dark-900 text-gray-100 font-sans selection:bg-brand-900 selection:text-white pb-20 md:pb-0">
      {/* Success Notification */}
      {showSuccessMessage && (
          <div className="fixed top-20 right-4 bg-green-600 text-white px-6 py-4 rounded-xl shadow-2xl z-50 animate-bounce">
              <span className="font-bold block mb-1">Sucesso!</span>
              {showSuccessMessage}
          </div>
      )}

      {/* Header (Desktop & Mobile Top) */}
      <header className="border-b border-dark-800 bg-dark-900/95 backdrop-blur sticky top-0 z-40">
        <div className="container mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2 cursor-pointer" onClick={() => setView('dashboard')}>
            <Flame className="text-brand-500" />
            <span className="font-bold text-xl tracking-tight text-white">Kink<span className="text-brand-500">Master</span></span>
          </div>

          {/* Desktop Nav */}
          <nav className="hidden md:flex gap-6 text-sm text-gray-400">
            <button onClick={() => setView('dashboard')} className={`hover:text-brand-400 transition-colors ${view === 'dashboard' ? 'text-white font-bold' : ''}`}>Biblioteca</button>
            <button onClick={handleChatClick} className={`hover:text-brand-400 transition-colors flex items-center gap-1 ${view === 'chat' ? 'text-white font-bold' : ''}`}>
               Chat Club {isSubscribed && <Lock size={12} className="text-brand-500" />}
            </button>
            <button onClick={() => setShowSubscriptionModal(true)} className="hover:text-brand-400 transition-colors flex items-center gap-1">
                {isSubscribed && <Crown size={14} className="text-brand-400" />} Assinatura
            </button>

            {/* ADMIN LINK */}
            {isAdmin && (
                <button onClick={() => setView('admin')} className={`hover:text-red-400 transition-colors flex items-center gap-1 ${view === 'admin' ? 'text-red-500 font-bold' : 'text-red-500/70'}`}>
                    <ShieldAlert size={14} /> Admin
                </button>
            )}
          </nav>

          {/* User Status (Desktop) */}
          <div className="hidden md:flex items-center gap-3">
             <div className="text-right">
               <div className="text-xs text-gray-400">
                   {userEmail ? 'Logado' : 'Bem-vindo,'}
               </div>
               <div className="text-sm font-bold text-white flex items-center justify-end gap-1">
                 {userEmail ? userEmail.split('@')[0] : 'Visitante'} 
                 {isSubscribed && <Crown size={12} className="text-brand-500" />}
               </div>
             </div>

             <button 
                onClick={handleUserClick}
                className={`w-10 h-10 rounded-full border flex items-center justify-center transition-all ${
                    isAdmin
                    ? 'bg-red-900 border-red-500 text-white'
                    : isSubscribed 
                    ? 'bg-brand-900 border-brand-500 text-brand-200 hover:bg-brand-800' 
                    : userEmail 
                        ? 'bg-blue-900 border-blue-500 text-blue-200 hover:bg-blue-800'
                        : 'bg-dark-800 border-dark-700 text-gray-400 hover:bg-dark-700 hover:text-white'
                }`}
             >
                <User size={20} />
             </button>
          </div>

          {/* Mobile Club Button */}
          <div className="md:hidden">
             <button onClick={() => setShowSubscriptionModal(true)} className="text-brand-500 font-bold text-sm flex items-center gap-1">
                Club <Crown size={16} />
             </button>
          </div>
        </div>
      </header>

      <main className="container mx-auto px-4 py-8 md:py-12">
        {view === 'dashboard' ? (
            <>
                <Dashboard 
                    unlockedIds={unlockedIds}
                    isSubscribed={isSubscribed}
                    onSelectLocked={setSelectedLockedFetish}
                    onSelectUnlocked={handleSelectUnlocked}
                    onOpenSubscribe={() => setShowSubscriptionModal(true)}
                />
                <div className="mt-16 mb-8">
                   <TrendChart />
                </div>
            </>
        ) : view === 'profile' ? (
            <Profile 
                userEmail={userEmail || 'Convidado'}
                isSubscribed={isSubscribed}
                unlockedIds={unlockedIds}
                onLogout={handleLogout}
                onRead={(id) => {
                    const fetish = FETISH_DATA.find(f => f.id === id);
                    if(fetish) handleSelectUnlocked(fetish);
                }}
                onOpenSubscribe={() => setShowSubscriptionModal(true)}
            />
        ) : view === 'chat' ? (
            <ClubChat 
                isSubscribed={isSubscribed}
                userEmail={userEmail}
                onOpenSubscribe={() => setShowSubscriptionModal(true)}
            />
        ) : view === 'admin' && isAdmin ? (
            <AdminPanel />
        ) : null}

        <section className="mt-20 border-t border-dark-800 pt-10 text-center text-gray-500 text-sm pb-10 md:pb-0">
          <div className="max-w-2xl mx-auto space-y-4">
             <div className="flex justify-center gap-4 mb-4">
                <Lock size={16} />
                <span>Ambiente Seguro e Discreto</span>
             </div>
             <p>© 2026 KinkMaster Brasil. Todos os direitos reservados.</p>
          </div>
        </section>
      </main>

      {/* Mobile Bottom Navigation */}
      <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-dark-900 border-t border-dark-800 flex justify-around p-3 z-50 pb-safe">
        {isAdmin && (
             <button 
                onClick={() => setView('admin')}
                className={`flex flex-col items-center gap-1 text-xs ${view === 'admin' ? 'text-red-500 font-bold' : 'text-gray-500'}`}
            >
                <ShieldAlert size={22} className={view === 'admin' ? "fill-red-500/20" : ""} />
                <span>Admin</span>
            </button>
        )}
        <button 
            onClick={() => setView('dashboard')}
            className={`flex flex-col items-center gap-1 text-xs ${view === 'dashboard' ? 'text-brand-500 font-bold' : 'text-gray-500'}`}
        >
            <Home size={22} />
            <span>Início</span>
        </button>
        <button 
            onClick={handleChatClick}
            className={`flex flex-col items-center gap-1 text-xs ${view === 'chat' ? 'text-brand-500 font-bold' : 'text-gray-500'}`}
        >
            <MessageCircle size={22} className={isSubscribed ? "text-brand-500" : ""} />
            <span>Chat</span>
        </button>
        <button 
            onClick={() => setShowSubscriptionModal(true)}
            className={`flex flex-col items-center gap-1 text-xs ${showSubscriptionModal ? 'text-brand-500 font-bold' : 'text-gray-500'}`}
        >
            <Crown size={22} className={isSubscribed ? "text-brand-500 fill-brand-500" : ""} />
            <span>Club</span>
        </button>
        <button 
            onClick={handleUserClick}
            className={`flex flex-col items-center gap-1 text-xs ${view === 'profile' ? 'text-brand-500 font-bold' : 'text-gray-500'}`}
        >
            <User size={22} />
            <span>Perfil</span>
        </button>
      </nav>

      {/* Modals */}
      {selectedLockedFetish && (
        <ProductFlow 
          fetish={selectedLockedFetish} 
          onClose={() => setSelectedLockedFetish(null)} 
          onUnlock={handleUnlock}
        />
      )}

      {showSubscriptionModal && (
        <SubscriptionModal 
            onClose={() => setShowSubscriptionModal(false)}
            onSubscribe={handleSubscribe}
        />
      )}

      {authModalState.isOpen && (
          <AuthModal 
            initialTab={authModalState.tab}
            onClose={() => setAuthModalState({ ...authModalState, isOpen: false })} 
          />
      )}

      {showCompleteRegistration && userEmail && (
          <CompleteRegistration 
              userEmail={userEmail}
              onComplete={() => {
                  setIsProfileComplete(true);
                  setShowCompleteRegistration(false);
              }}
          />
      )}
    </div>
  );
};

export default App;

import React, { useEffect, useState } from 'react';
import { User, Crown, BookOpen, LogOut, ShieldCheck, Edit3 } from 'lucide-react';
import { FETISH_DATA } from '../constants';
import { supabase } from '../lib/supabase';

interface Props {
  userEmail: string;
  isSubscribed: boolean;
  unlockedIds: string[];
  onLogout: () => void;
  onRead: (fetishId: string) => void;
  onOpenSubscribe: () => void;
}

const Profile: React.FC<Props> = ({ userEmail, isSubscribed, unlockedIds, onLogout, onRead, onOpenSubscribe }) => {
  const myCourses = FETISH_DATA.filter(f => unlockedIds.includes(f.id));
  const [profileData, setProfileData] = useState<{name: string, avatar: string, phone: string, cep: string} | null>(null);

  useEffect(() => {
     if(supabase) {
        supabase.from('profiles').select('*').eq('email', userEmail).single().then(({data}) => {
            if(data) {
                setProfileData({
                    name: data.full_name,
                    avatar: data.avatar_url,
                    phone: data.phone,
                    cep: data.cep
                });
            }
        });
     }
  }, [userEmail]);

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      {/* Header do Perfil */}
      <div className="bg-dark-800 rounded-2xl p-8 border border-dark-700 flex flex-col md:flex-row items-center gap-8 relative overflow-hidden">
        <div className="absolute top-0 right-0 p-32 bg-brand-900/20 blur-3xl rounded-full translate-x-10 -translate-y-10"></div>

        <div className="w-24 h-24 rounded-full bg-dark-700 border-2 border-brand-500 flex items-center justify-center shrink-0 relative z-10 overflow-hidden">
           {profileData?.avatar ? (
              <img src={profileData.avatar} alt="Avatar" className="w-full h-full object-cover" />
           ) : (
              <User size={40} className="text-gray-300" />
           )}

           {isSubscribed && (
               <div className="absolute bottom-0 right-0 bg-brand-500 p-1 rounded-full border border-dark-900">
                   <Crown size={12} className="text-white" />
               </div>
           )}
        </div>

        <div className="text-center md:text-left flex-1 relative z-10">
           <h2 className="text-2xl font-bold text-white mb-1">{profileData?.name || "Usuário"}</h2>
           <p className="text-gray-400 font-mono text-sm mb-4">{userEmail}</p>

           <div className="flex flex-wrap gap-3 justify-center md:justify-start">
              <span className={`px-3 py-1 rounded-full text-xs font-bold border ${isSubscribed ? 'bg-brand-900/30 border-brand-500 text-brand-400' : 'bg-dark-700 border-dark-600 text-gray-400'}`}>
                  {isSubscribed ? 'Membro Club VIP' : 'Membro Gratuito'}
              </span>
              <span className="px-3 py-1 rounded-full text-xs font-bold bg-dark-700 border border-dark-600 text-gray-400">
                  {unlockedIds.length} Guias Adquiridos
              </span>
           </div>

           {/* Info Extra */}
           {profileData && (
              <div className="mt-4 text-xs text-gray-500 grid grid-cols-2 gap-4 max-w-xs mx-auto md:mx-0 border-t border-dark-700 pt-2">
                 <div>
                    <span className="block font-bold">Telefone</span>
                    <span>{profileData.phone}</span>
                 </div>
                 <div>
                    <span className="block font-bold">CEP</span>
                    <span>{profileData.cep}</span>
                 </div>
              </div>
           )}
