        <button 
           onClick={onLogout}
           className="px-4 py-2 bg-dark-900 hover:bg-red-900/30 border border-dark-600 hover:border-red-500/50 text-gray-400 hover:text-red-400 rounded-lg text-sm transition-all flex items-center gap-2 relative z-10"
        >
           <LogOut size={16} /> Sair
        </button>
      </div>

      {/* Seção de Assinatura */}
      {!isSubscribed && (
         <div className="bg-gradient-to-r from-brand-900/40 to-dark-800 border border-brand-900/50 rounded-2xl p-6 md:p-8 flex flex-col md:flex-row items-center justify-between gap-6">
            <div>
               <h3 className="text-xl font-bold text-white mb-2 flex items-center gap-2">
                  <Crown className="text-brand-500" size={24} /> Torne-se Membro Club
               </h3>
               <p className="text-gray-400 text-sm max-w-md">
                  Desbloqueie acesso ao Mentor IA, receba contos exclusivos semanais e tenha 50% de desconto em todos os novos guias.
               </p>
            </div>
            <button 
                onClick={onOpenSubscribe}
                className="bg-brand-600 hover:bg-brand-500 text-white px-6 py-3 rounded-xl font-bold transition-colors whitespace-nowrap shadow-lg shadow-brand-900/20"
            >
                Ativar Assinatura VIP
            </button>
         </div>
      )}

      {/* Lista de Cursos */}
      <div>
         <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2 border-b border-dark-800 pb-4">
            <BookOpen size={20} className="text-brand-400" /> Meus Guias
         </h3>

         {myCourses.length > 0 ? (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
               {myCourses.map(fetish => (
                  <div key={fetish.id} className="bg-dark-800 rounded-xl p-4 border border-dark-700 flex gap-4 hover:border-brand-500/50 transition-colors group">
                     <div className="w-16 h-16 rounded-lg bg-dark-700 shrink-0 overflow-hidden relative">
                         <img src={fetish.image} alt={fetish.title} className="w-full h-full object-cover opacity-70 group-hover:opacity-100 transition-opacity" />
                     </div>
                     <div className="flex-1 min-w-0">
                        <h4 className="font-bold text-white truncate group-hover:text-brand-400 transition-colors">{fetish.title}</h4>
                        <p className="text-xs text-green-500 flex items-center gap-1 mt-1">
                           <ShieldCheck size={12} /> Acesso Vitalício
                        </p>
                        <button 
                            onClick={() => onRead(fetish.id)}
