                            Continuar Leitura
                        </button>
                     </div>
                  </div>
               ))}
            </div>
         ) : (
            <div className="text-center py-12 bg-dark-800/30 rounded-xl border border-dashed border-dark-700">
               <p className="text-gray-500 mb-2">Sua biblioteca está vazia.</p>
               <p className="text-sm text-gray-600">Explore o catálogo para começar sua jornada.</p>
            </div>
         )}
      </div>
    </div>
  );
};

