import React, { useState } from 'react';
import { supabase } from '../lib/supabase';
import { User, Phone, MapPin, CheckCircle, Sticker, Upload, Image as ImageIcon } from 'lucide-react';

interface Props {
  userEmail: string;
  onComplete: () => void;
}

const AVATARS = [
  { id: 'av1', url: 'https://cdn-icons-png.flaticon.com/512/4140/4140048.png' },
  { id: 'av2', url: 'https://cdn-icons-png.flaticon.com/512/4140/4140047.png' },
  { id: 'av3', url: 'https://cdn-icons-png.flaticon.com/512/4140/4140037.png' },
  { id: 'av4', url: 'https://cdn-icons-png.flaticon.com/512/4140/4140051.png' },
  { id: 'av5', url: 'https://cdn-icons-png.flaticon.com/512/924/924915.png' },
  { id: 'av6', url: 'https://cdn-icons-png.flaticon.com/512/924/924874.png' },
];

const CompleteRegistration: React.FC<Props> = ({ userEmail, onComplete }) => {
  const [fullName, setFullName] = useState('');
  const [phone, setPhone] = useState('');
  const [cep, setCep] = useState('');
  const [selectedAvatar, setSelectedAvatar] = useState(AVATARS[0].url);
  const [loading, setLoading] = useState(false);

  // Lógica simples para converter upload em base64 e salvar como URL (para protótipo sem bucket)
  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 500000) { // 500kb limit for base64 safety in text fields
        alert("A imagem deve ter menos de 500kb.");
        return;
      }
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedAvatar(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!supabase) return;
    setLoading(true);

    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("Usuário não encontrado.");

      const updates = {
        id: user.id,
        email: userEmail,
        full_name: fullName,
        phone,
        cep,
        avatar_url: selectedAvatar,
        updated_at: new Date(),
      };

      const { error } = await supabase.from('profiles').upsert(updates);
      if (error) throw error;

      onComplete();
    } catch (error) {
      console.error(error);
      alert('Erro ao salvar perfil. Tente novamente.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/95 backdrop-blur-md p-4 overflow-y-auto">
      <div className="bg-dark-900 border border-brand-500 rounded-2xl w-full max-w-lg p-6 md:p-8 relative shadow-2xl animate-in fade-in zoom-in duration-300">

        <div className="text-center mb-6">
           <h2 className="text-2xl font-bold text-white mb-2">Finalize seu Perfil</h2>
           <p className="text-gray-400 text-sm">Identidade segura para a comunidade KinkClub.</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">

           {/* Avatar Section */}
           <div className="flex flex-col items-center mb-6">
              <div className="w-24 h-24 rounded-full border-2 border-brand-500 p-1 mb-4 relative group">
                  <img src={selectedAvatar} alt="Avatar" className="w-full h-full object-cover rounded-full" />
                  <label htmlFor="avatar-upload" className="absolute inset-0 bg-black/50 rounded-full flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity cursor-pointer">
                      <Upload size={20} className="text-white" />
                  </label>
                  <input id="avatar-upload" type="file" accept="image/*" className="hidden" onChange={handleImageUpload} />
              </div>

              <div className="w-full">
                  <p className="text-xs text-gray-500 text-center mb-2 uppercase font-bold">Ou escolha uma figurinha</p>
                  <div className="flex gap-3 justify-center flex-wrap">
                    {AVATARS.map((av) => (
                        <button
                          key={av.id}
                          type="button"
                          onClick={() => setSelectedAvatar(av.url)}
                          className={`w-10 h-10 rounded-full border-2 transition-all ${selectedAvatar === av.url ? 'border-brand-500 scale-110' : 'border-dark-700 opacity-50'}`}
                        >
                          <img src={av.url} className="w-full h-full rounded-full" />
                        </button>
                    ))}
                  </div>
              </div>
           </div>

           <div>
              <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Nome no App</label>
              <div className="relative">
                 <User className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-600" size={18} />
                 <input 
                   type="text" 
                   required
                   value={fullName}
                   onChange={e => setFullName(e.target.value)}
                   className="w-full bg-dark-800 border border-dark-600 rounded-xl py-3 pl-10 pr-4 text-white focus:border-brand-500 focus:outline-none"
                   placeholder="Apelido ou Nome Real"
                 />
              </div>
           </div>

           <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                 <label className="block text-xs font-bold text-gray-500 uppercase mb-1">WhatsApp</label>
                 <div className="relative">
                    <Phone className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-600" size={18} />
                    <input 
                      type="tel" 
                      required
                      value={phone}
                      onChange={e => setPhone(e.target.value)}
                      className="w-full bg-dark-800 border border-dark-600 rounded-xl py-3 pl-10 pr-4 text-white focus:border-brand-500 focus:outline-none"
                      placeholder="(DD) 99999-9999"
                    />
                 </div>
              </div>
              <div>
                 <label className="block text-xs font-bold text-gray-500 uppercase mb-1">CEP</label>
                 <div className="relative">
                    <MapPin className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-600" size={18} />
                    <input 
                      type="text" 
                      required
                      value={cep}
                      onChange={e => setCep(e.target.value)}
                      className="w-full bg-dark-800 border border-dark-600 rounded-xl py-3 pl-10 pr-4 text-white focus:border-brand-500 focus:outline-none"
                      placeholder="00000-000"
                    />
                 </div>
              </div>
           </div>

           <button 
             type="submit" 
             disabled={loading}
             className="w-full bg-brand-600 hover:bg-brand-500 text-white font-bold py-4 rounded-xl transition-all flex items-center justify-center gap-2 shadow-lg shadow-brand-900/30 mt-4"
           >
              {loading ? 'Processando...' : <><CheckCircle size={20} /> Entrar no Club</>}
           </button>
