    e.preventDefault();
    if (!supabase) return;

    if(!preference) {
        alert("Por favor, selecione como você se identifica para personalizarmos o conteúdo.");
        return;
    }

    setLoading(true);

    try {
      const { data: { user } } = await supabase.auth.getUser();
