import React, { useState, useEffect } from 'react';
import { supabase } from './lib/supabase';
import { FETISH_DATA } from './constants';
import { FetishData, TargetAudience } from './types';
import ProductFlow from './components/ProductFlow';
import Dashboard from './components/Dashboard';
import CoursePlayer from './components/CoursePlayer';
import SubscriptionModal from './components/SubscriptionModal';
import AuthModal from './components/AuthModal';
import Profile from './components/Profile';
import ClubChat from './components/ClubChat';
import ClubLanding from './components/ClubLanding';
import AdminPanel, { CONST_ADMIN_EMAIL } from './components/AdminPanel';
import CompleteRegistration from './components/CompleteRegistration';
import PublicHome from './components/PublicHome';
import { Flame, User, Crown, Home, ShieldAlert, LogOut } from 'lucide-react';
import { useContentAccess } from './hooks/useContentAccess';

const App: React.FC = () => {
  const { unlockedIds, isSubscribed, unlockContent, userEmail, signOut } = useContentAccess();

  // Navigation State
  const [view, setView] = useState<'dashboard' | 'player' | 'profile' | 'club' | 'admin'>('dashboard');

  // Data State
  const [userPreference, setUserPreference] = useState<TargetAudience | null>(null);
  const [loadingProfile, setLoadingProfile] = useState(false);

  // Modals & Flows
  const [selectedLockedFetish, setSelectedLockedFetish] = useState<FetishData | null>(null);
  const [currentCourse, setCurrentCourse] = useState<{fetish: FetishData, audience: TargetAudience} | null>(null);
  const [showSubscriptionModal, setShowSubscriptionModal] = useState(false);
  const [authModalState, setAuthModalState] = useState<{ isOpen: boolean; tab: 'login' | 'signup' }>({ 
      isOpen: false, 
      tab: 'login' 
  });

  const [showCompleteRegistration, setShowCompleteRegistration] = useState(false);
  const [showSuccessMessage, setShowSuccessMessage] = useState<string | null>(null);

  // 1. Fetch Profile Preference on Login
  useEffect(() => {
    if (userEmail && supabase) {
        setLoadingProfile(true);
        const checkProfile = async () => {
            const { data } = await supabase
                .from('profiles')
                .select('preference')
                .eq('email', userEmail)
                .single();

            if (data && data.preference) {
                setUserPreference(data.preference as TargetAudience);
                setShowCompleteRegistration(false);
            } else {
                // Se não tem preferência, força o cadastro
                setShowCompleteRegistration(true);
            }
            setLoadingProfile(false);
        };
        checkProfile();
    } else {
        setUserPreference(null);
        setShowCompleteRegistration(false);
    }
  }, [userEmail]);

  // 2. URL Params Handler (Post-checkout Ticto)
  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const status = params.get('status');
    const fid = params.get('fid');
    const type = params.get('type');

    if (status === 'success') {
       if (type === 'sub') {
           unlockContent('club', 'sub');
           setShowSuccessMessage("Parabéns! Bem-vindo ao KinkClub.");
       } else if (fid) {
           unlockContent(fid, 'course');
           setShowSuccessMessage("Guia desbloqueado com sucesso!");
       }
       // Limpa URL
       window.history.replaceState({}, document.title, "/");
       setTimeout(() => setShowSuccessMessage(null), 5000);
    }
  }, [unlockContent]);

  // --- RENDERING LOGIC ---

  // 1. Not Logged In -> Public Home (Gatewall)
  if (!userEmail) {
    return (
      <>
        <PublicHome 
          onLogin={() => setAuthModalState({ isOpen: true, tab: 'login' })}
          onSignup={() => setAuthModalState({ isOpen: true, tab: 'signup' })}
        />
        {authModalState.isOpen && (
          <AuthModal 
            initialTab={authModalState.tab} 
            onClose={() => setAuthModalState({ ...authModalState, isOpen: false })} 
          />
        )}
      </>
    );
  }

  // 2. Logged In but Profile Incomplete -> Force Registration
  if (showCompleteRegistration && !loadingProfile) {
      return (
          <CompleteRegistration 
              userEmail={userEmail}
              onComplete={(pref) => {
                  setUserPreference(pref);
                  setShowCompleteRegistration(false);
              }}
          />
      );
  }

  // 3. Logged In & Complete -> Main App
  // MODO ADMIN FORÇADO PARA PREVIEW
  const isAdmin = true; 

  return (
    <div className="min-h-screen bg-dark-900 text-gray-100 font-sans pb-20 md:pb-0">

      {/* Navbar Desktop */}
      <nav className="border-b border-dark-800 bg-dark-900/95 backdrop-blur sticky top-0 z-40 hidden md:block">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex items-center justify-between h-16">
            <div className="flex items-center gap-2 cursor-pointer" onClick={() => setView('dashboard')}>
              <Flame className="text-brand-500" />
              <span className="font-bold text-xl tracking-tight">Kink<span className="text-brand-500">Master</span></span>
            </div>

            <div className="flex items-baseline space-x-4">
              <button onClick={() => setView('dashboard')} className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${view === 'dashboard' ? 'text-white bg-dark-800' : 'text-gray-300 hover:text-white hover:bg-dark-700'}`}>Dashboard</button>
              <button onClick={() => setView('club')} className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${view === 'club' ? 'text-brand-400 bg-brand-900/20' : 'text-gray-300 hover:text-brand-400'}`}>Club VIP</button>
              <button onClick={() => setView('profile')} className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${view === 'profile' ? 'text-white bg-dark-800' : 'text-gray-300 hover:text-white hover:bg-dark-700'}`}>Meu Perfil</button>
              {isAdmin && (
                <button onClick={() => setView('admin')} className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${view === 'admin' ? 'text-red-400 bg-red-900/20' : 'text-gray-300 hover:text-red-400'}`}>Admin</button>
              )}
              <button onClick={signOut} className="ml-4 p-2 text-gray-500 hover:text-white"><LogOut size={18} /></button>
            </div>
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {/* Success Toast */}
        {showSuccessMessage && (
            <div className="mb-6 p-4 bg-green-900/30 border border-green-500/50 rounded-xl text-green-400 flex items-center justify-center animate-in slide-in-from-top-4 fade-in">
                <span className="font-bold">{showSuccessMessage}</span>
            </div>
        )}

        {/* View Switcher */}
        {view === 'dashboard' && (
           <Dashboard 
              unlockedIds={unlockedIds}
              isSubscribed={isSubscribed}
              onSelectLocked={(fetish) => setSelectedLockedFetish(fetish)}
              onSelectUnlocked={(fetish) => setCurrentCourse({ fetish, audience: userPreference || 'Homens' })}
              onOpenSubscribe={() => setShowSubscriptionModal(true)}
           />
        )}

        {view === 'player' && currentCourse && (
            <CoursePlayer 
                fetish={currentCourse.fetish}
                audience={currentCourse.audience} 
                onBack={() => setView('dashboard')}
            />
        )}

        {view === 'profile' && (
            <Profile 
                userEmail={userEmail}
                isSubscribed={isSubscribed}
                unlockedIds={unlockedIds}
                onLogout={signOut}
                onRead={(fid) => {
                    const fetish = FETISH_DATA.find(f => f.id === fid);
                    if (fetish) {
                        setCurrentCourse({ fetish, audience: userPreference || 'Homens' });
                        setView('player');
                    }
                }}
                onOpenSubscribe={() => setShowSubscriptionModal(true)}
            />
        )}

        {view === 'club' && (
           <div className="animate-in fade-in zoom-in duration-300">
               {isSubscribed ? (
                   <ClubChat 
                      isSubscribed={true} 
                      userEmail={userEmail}
                      onOpenSubscribe={() => setShowSubscriptionModal(true)}
                   />
               ) : (
                   <ClubLanding onSubscribe={() => setShowSubscriptionModal(true)} />
               )}
           </div>
        )}

        {view === 'admin' && isAdmin && (
            <AdminPanel />
        )}

      </main>

      {/* Mobile Tab Bar */}
      <div className="md:hidden fixed bottom-0 left-0 right-0 bg-dark-900 border-t border-dark-800 p-2 flex justify-around z-40 pb-safe">
        <button onClick={() => setView('dashboard')} className={`flex flex-col items-center p-2 rounded-lg ${view === 'dashboard' ? 'text-brand-500' : 'text-gray-500'}`}>
           <Home size={24} />
           <span className="text-[10px] font-bold mt-1">Início</span>
        </button>
        <button onClick={() => setView('club')} className={`flex flex-col items-center p-2 rounded-lg ${view === 'club' ? 'text-brand-500' : 'text-gray-500'}`}>
           <Crown size={24} />
           <span className="text-[10px] font-bold mt-1">Club</span>
        </button>
        {isAdmin && (
             <button onClick={() => setView('admin')} className={`flex flex-col items-center p-2 rounded-lg ${view === 'admin' ? 'text-red-500' : 'text-gray-500'}`}>
                <ShieldAlert size={24} />
                <span className="text-[10px] font-bold mt-1">Admin</span>
             </button>
        )}
        <button onClick={() => setView('profile')} className={`flex flex-col items-center p-2 rounded-lg ${view === 'profile' ? 'text-brand-500' : 'text-gray-500'}`}>
           <User size={24} />
           <span className="text-[10px] font-bold mt-1">Perfil</span>
        </button>
      </div>

      {/* Product Flow Modal (Sales) */}
      {selectedLockedFetish && (
        <ProductFlow 
          fetish={selectedLockedFetish}
          userPreference={userPreference || undefined} // Passa a preferência para pular a seleção
          onClose={() => setSelectedLockedFetish(null)}
          onUnlock={(id, audience) => {
             // Mock unlock for simulation (real unlock happens via URL callback)
             setSelectedLockedFetish(null);
          }}
        />
      )}

      {/* Subscription Modal */}
      {showSubscriptionModal && (
          <SubscriptionModal 
             onClose={() => setShowSubscriptionModal(false)}
             onSubscribe={() => {}}
          />
      )}

    </div>
  );
};

export default App;

