          userPreference={userPreference || undefined}
          onClose={() => setSelectedLockedFetish(null)}
          onUnlock={(id, audience) => setSelectedLockedFetish(null)}
        />
      )}

      {/* Subscription Modal */}
      {showSubscriptionModal && (
          <SubscriptionModal 
             onClose={() => setShowSubscriptionModal(false)}
             onSubscribe={() => {}}
          />
      )}

    </div>
  );
};

export default App;

import React from 'react';
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  Cell
} from 'recharts';
import { FETISH_DATA } from '../constants';

const TrendChart: React.FC = () => {
  const data = FETISH_DATA.map(f => ({
    // Simplificado: Se contém "Anal" no título, exibe apenas "Anal", senão pega a primeira palavra
    name: f.title.includes('Anal') ? 'Anal' : f.title.split(' ')[0],
    fullTitle: f.title,
    popularity: f.popularity,
  })).sort((a, b) => b.popularity - a.popularity);

  return (
    <div className="w-full h-[300px] md:h-[400px] bg-dark-800/50 rounded-xl p-4 border border-brand-900/30">
      <h3 className="text-brand-300 mb-4 font-semibold text-sm uppercase tracking-wider">
        Tendências Nacionais 2025/2026 (%)
      </h3>
      <ResponsiveContainer width="100%" height="100%">
        <BarChart
          data={data}
          margin={{
            top: 5,
            right: 10,
            left: -20,
            bottom: 5,
          }}
        >
          <CartesianGrid strokeDasharray="3 3" stroke="#333" vertical={false} />
          <XAxis 
            dataKey="name" 
            stroke="#9ca3af" 
            tick={{ fontSize: 10 }} 
            interval={0}
            angle={-45}
            textAnchor="end"
            height={60}
          />
          <YAxis stroke="#9ca3af" tick={{ fontSize: 12 }} />
          <Tooltip 
            contentStyle={{ backgroundColor: '#18181b', borderColor: '#831843', color: '#f4f4f5' }}
            itemStyle={{ color: '#f472b6' }}
            cursor={{ fill: '#831843', opacity: 0.2 }}
          />
          <Bar dataKey="popularity" radius={[4, 4, 0, 0]}>
            {data.map((entry, index) => (
              <Cell key={`cell-${index}`} fill={index < 3 ? '#db2777' : '#831843'} />
            ))}
          </Bar>
        </BarChart>
      </ResponsiveContainer>
    </div>
  );
};

