           <button 
             onClick={() => setActiveFilter('Mulheres')}
             className={`px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 transition-all ${activeFilter === 'Mulheres' ? 'bg-pink-900/50 text-pink-400 shadow' : 'text-gray-500 hover:text-gray-300'}`}
           >
             <Venus size={16} /> Mulheres
