           <button 
             onClick={() => setActiveFilter('LGBT+')}
             className={`px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 transition-all ${activeFilter === 'LGBT+' ? 'bg-purple-900/50 text-purple-400 shadow' : 'text-gray-500 hover:text-gray-300'}`}
