      {/* Meus Guias */}
      {myCourses.length > 0 && (
        <section>
          <h2 className="text-2xl font-bold text-white mb-6 flex items-center gap-2">
             <BookOpen className="text-brand-500 fill-brand-500" size={24} /> Minha Biblioteca
