           ) : (
              <User size={40} className="text-gray-300" />
           )}

           {isSubscribed && (
               <div className="absolute bottom-0 right-0 bg-brand-500 p-1 rounded-full border border-dark-900">
                   <Crown size={12} className="text-white" />
               </div>
           )}
        </div>

        <div className="text-center md:text-left flex-1 relative z-10">
           <h2 className="text-2xl font-bold text-white mb-1">{profileData?.full_name || "Usuário"}</h2>
           <p className="text-gray-400 font-mono text-sm mb-4">{userEmail}</p>

           <div className="flex flex-wrap gap-3 justify-center md:justify-start">
              <span className={`px-3 py-1 rounded-full text-xs font-bold border ${isSubscribed ? 'bg-brand-900/30 border-brand-500 text-brand-400' : 'bg-dark-700 border-dark-600 text-gray-400'}`}>
                  {isSubscribed ? 'Membro Club VIP' : 'Membro Gratuito'}
              </span>
              <span className="px-3 py-1 rounded-full text-xs font-bold bg-dark-700 border border-dark-600 text-gray-400">
                  {unlockedIds.length} Guias Adquiridos
              </span>
           </div>

           {/* Info Extra */}
           {profileData && (
              <div className="mt-4 text-xs text-gray-500 grid grid-cols-2 md:grid-cols-4 gap-4 max-w-lg mx-auto md:mx-0 border-t border-dark-700 pt-2">
                 <div>
                    <span className="block font-bold mb-1">Telefone</span>
                    <span>{profileData.phone}</span>
                 </div>
                 {profileData.city && (
                    <div className="col-span-2">
                        <span className="block font-bold mb-1">Localização</span>
                        <span className="flex items-center gap-1 justify-center md:justify-start">
                            <MapPin size={10} /> {profileData.city} - {profileData.state}
                        </span>
                    </div>
                 )}
                 {profileData.birth_date && (
                    <div>
                        <span className="block font-bold mb-1">Idade</span>
                        <span className="flex items-center gap-1 justify-center md:justify-start">
                            <Calendar size={10} /> {getAge(profileData.birth_date)} anos
                        </span>
                    </div>
                 )}
              </div>
           )}
        </div>

        <button 
           onClick={onLogout}
           className="px-4 py-2 bg-dark-900 hover:bg-red-900/30 border border-dark-600 hover:border-red-500/50 text-gray-400 hover:text-red-400 rounded-lg text-sm transition-all flex items-center gap-2 relative z-10"
        >
           <LogOut size={16} /> Sair
        </button>
      </div>

      {/* Seção de Assinatura */}
      {!isSubscribed && (
         <div className="bg-gradient-to-r from-brand-900/40 to-dark-800 border border-brand-900/50 rounded-2xl p-6 md:p-8 flex flex-col md:flex-row items-center justify-between gap-6">
            <div>
               <h3 className="text-xl font-bold text-white mb-2 flex items-center gap-2">
                  <Crown className="text-brand-500" size={24} /> Torne-se Membro Club
               </h3>
               <p className="text-gray-400 text-sm max-w-md">
                  Desbloqueie acesso ao Mentor IA, receba contos exclusivos semanais e tenha 50% de desconto em todos os novos guias.
               </p>
            </div>
            <button 
                onClick={onOpenSubscribe}
                className="bg-brand-600 hover:bg-brand-500 text-white px-6 py-3 rounded-xl font-bold transition-colors whitespace-nowrap shadow-lg shadow-brand-900/20"
            >
                Ativar Assinatura VIP
            </button>
         </div>
      )}

      {/* Lista de Cursos */}
      <div>
         <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2 border-b border-dark-800 pb-4">
            <BookOpen size={20} className="text-brand-400" /> Meus Guias
