import React, { useState } from 'react';
import { supabase } from '../lib/supabase';
import { FETISH_DATA } from '../constants';
import { ShieldAlert, Save, Trash2, Search, CheckCircle, XCircle } from 'lucide-react';

// === CONFIGURAÇÃO ===
// Coloque aqui o seu email de admin (o mesmo que usou no SQL do Supabase)
export const CONST_ADMIN_EMAIL = "guilhermesoaresc2@gmail.com"; 

const AdminPanel: React.FC = () => {
  const [targetEmail, setTargetEmail] = useState('');
  const [accessType, setAccessType] = useState<'subscription' | 'course'>('course');
  const [itemId, setItemId] = useState('anal'); // Default selection
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState<{ type: 'success' | 'error', text: string } | null>(null);

  const handleGrantAccess = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!supabase) return;
    setLoading(true);
    setMessage(null);

    try {
      // 1. Verificar se já existe
      const { data: existing } = await supabase
        .from('user_access')
        .select('id')
        .eq('user_email', targetEmail)
        .eq('item_id', accessType === 'subscription' ? 'club_membership' : itemId)
        .single();

      if (existing) {
        throw new Error("Este usuário já possui este acesso.");
      }

      // 2. Inserir
      const { error } = await supabase
        .from('user_access')
        .insert({
          user_email: targetEmail,
          access_type: accessType,
          item_id: accessType === 'subscription' ? 'club_membership' : itemId
        });

      if (error) throw error;

      setMessage({ type: 'success', text: `Acesso liberado para ${targetEmail}!` });
      setTargetEmail(''); // Limpar campo para próxima inserção

    } catch (err: any) {
      setMessage({ type: 'error', text: err.message });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-2xl mx-auto mt-8">
      <div className="bg-dark-800 border border-red-900/50 rounded-2xl p-6 shadow-2xl relative overflow-hidden">
        {/* Header Admin */}
        <div className="flex items-center gap-3 mb-6 border-b border-dark-700 pb-4">
          <div className="bg-red-900/20 p-3 rounded-full">
            <ShieldAlert className="text-red-500" size={24} />
          </div>
          <div>
            <h2 className="text-xl font-bold text-white">Painel Administrativo</h2>
            <p className="text-xs text-gray-500">Acesso restrito. Use com cautela.</p>
          </div>
        </div>

        {/* Feedback Message */}
        {message && (
          <div className={`p-4 rounded-xl mb-6 flex items-center gap-3 ${message.type === 'success' ? 'bg-green-900/20 text-green-400 border border-green-900' : 'bg-red-900/20 text-red-400 border border-red-900'}`}>
            {message.type === 'success' ? <CheckCircle size={20} /> : <XCircle size={20} />}
            <span className="text-sm font-semibold">{message.text}</span>
          </div>
        )}

        {/* Form */}
        <form onSubmit={handleGrantAccess} className="space-y-6">

          {/* Email do Usuário */}
          <div>
            <label className="block text-xs font-bold text-gray-500 uppercase mb-1">E-mail do Cliente</label>
            <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-600" size={18} />
                <input 
                  type="email" 
                  required
                  value={targetEmail}
                  onChange={(e) => setTargetEmail(e.target.value)}
                  placeholder="cliente@exemplo.com"
                  className="w-full bg-dark-900 border border-dark-600 rounded-xl py-3 pl-10 pr-4 text-white focus:border-red-500 focus:outline-none transition-colors"
                />
            </div>
          </div>

          {/* Tipo de Acesso */}
          <div className="grid grid-cols-2 gap-4">
            <button
              type="button"
              onClick={() => setAccessType('subscription')}
              className={`p-4 rounded-xl border flex flex-col items-center gap-2 transition-all ${accessType === 'subscription' ? 'bg-red-900/20 border-red-500 text-white' : 'bg-dark-900 border-dark-600 text-gray-500 hover:border-gray-500'}`}
            >
              <span className="font-bold">Liberar Club</span>
              <span className="text-[10px] uppercase">Assinatura</span>
            </button>

            <button
              type="button"
              onClick={() => setAccessType('course')}
              className={`p-4 rounded-xl border flex flex-col items-center gap-2 transition-all ${accessType === 'course' ? 'bg-brand-900/20 border-brand-500 text-white' : 'bg-dark-900 border-dark-600 text-gray-500 hover:border-gray-500'}`}
            >
              <span className="font-bold">Liberar Guia</span>
              <span className="text-[10px] uppercase">Curso Avulso</span>
            </button>
          </div>

          {/* Seletor de Curso (Só aparece se for 'course') */}
          {accessType === 'course' && (
             <div className="animate-in fade-in slide-in-from-top-2">
                <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Selecione o Guia</label>
                <select 
                  value={itemId}
                  onChange={(e) => setItemId(e.target.value)}
                  className="w-full bg-dark-900 border border-dark-600 rounded-xl py-3 px-4 text-white focus:border-brand-500 focus:outline-none"
                >
                  {FETISH_DATA.map(f => (
                    <option key={f.id} value={f.id}>{f.title}</option>
                  ))}
                </select>
             </div>
          )}

          <div className="pt-4 border-t border-dark-700">
             <button 
               type="submit" 
               disabled={loading || !targetEmail}
               className="w-full bg-white text-dark-900 font-bold py-3 rounded-xl hover:bg-gray-200 transition-colors flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
             >
               {loading ? 'Processando...' : <><Save size={18} /> Conceder Acesso Manualmente</>}
             </button>
          </div>

        </form>
      </div>
    </div>
  );
};

