import React, { useState, useEffect } from 'react';
import { FETISH_DATA } from '../constants';
import { FetishData, TargetAudience } from '../types';
import { Lock, BookOpen, Star, ChevronRight, Crown, Users, Mars, Venus, Sparkles, MapPin } from 'lucide-react';
import * as LucideIcons from 'lucide-react';
import { supabase } from '../lib/supabase';

interface Props {
  unlockedIds: string[];
  isSubscribed?: boolean;
  userPreference?: TargetAudience;
  onSelectLocked: (fetish: FetishData, audience: TargetAudience) => void;
  onSelectUnlocked: (fetish: FetishData, audience: TargetAudience) => void;
  onOpenSubscribe: () => void;
}

const Dashboard: React.FC<Props> = ({ unlockedIds, isSubscribed = false, userPreference, onSelectLocked, onSelectUnlocked, onOpenSubscribe }) => {
  const [activeFilter, setActiveFilter] = useState<TargetAudience>('Homens');
  const [userLocation, setUserLocation] = useState<string | null>(null);
  const [userName, setUserName] = useState<string>("Membro");

  useEffect(() => {
    if (userPreference) {
      setActiveFilter(userPreference);
    }
  }, [userPreference]);

  useEffect(() => {
    const fetchUserData = async () => {
        if(!supabase) return;
        const { data: { user } } = await supabase.auth.getUser();
        if(user) {
            const { data } = await supabase
              .from('profiles')
              .select('full_name, city, state')
              .eq('email', user.email)
              .single();

            if(data) {
                if(data.full_name) setUserName(data.full_name.split(' ')[0]); // Pega o primeiro nome
                if(data.city) setUserLocation(`${data.city}/${data.state}`);
            }
        }
    };
    fetchUserData();
  }, []);

  const myCourses = FETISH_DATA.filter(f => unlockedIds.includes(f.id));
  const exploreCourses = FETISH_DATA.filter(f => !unlockedIds.includes(f.id));

  const renderIcon = (iconName: string, size = 32) => {
    const Icon = (LucideIcons as any)[iconName] || LucideIcons.HelpCircle;
    return <Icon size={size} className="text-white" />;
  };

  const getStatText = (fetish: FetishData) => {
    switch (activeFilter) {
      case 'Homens': return fetish.stats.men;
      case 'Mulheres': return fetish.stats.women;
      case 'LGBT+': return fetish.stats.lgbt;
      default: return fetish.stats.men;
    }
  };

  return (
    <div className="space-y-12 animate-in fade-in duration-500">

      {/* Greeting / Location Banner */}
      <div className="flex flex-col md:flex-row justify-between items-end gap-4">
         <div>
            <h1 className="text-3xl font-bold text-white">
                Olá, <span className="text-brand-500">{userName}</span>
            </h1>
            <p className="text-gray-400 text-sm mt-1">
               {userLocation ? (
                 <span className="flex items-center gap-1"><MapPin size={12} className="text-brand-500"/> Tendências para {userLocation}</span>
               ) : (
                 "Explore o universo de possibilidades."
               )}
            </p>
         </div>
      </div>

      {/* Banner KinkClub */}
      {!isSubscribed && (
        <section className="bg-gradient-to-r from-brand-900 to-purple-900 rounded-2xl p-1 shadow-2xl relative overflow-hidden group cursor-pointer" onClick={onOpenSubscribe}>
            <div className="bg-dark-900/10 backdrop-blur-sm rounded-xl p-6 md:p-8 flex flex-col md:flex-row items-center justify-between gap-6 relative z-10">
                <div className="flex items-center gap-6">
                    <div className="w-16 h-16 bg-white/10 rounded-full flex items-center justify-center shrink-0 border border-white/20 animate-pulse">
                        <Crown size={32} className="text-brand-300" />
                    </div>
                    <div>
                        <h3 className="text-2xl font-bold text-white mb-1">KinkClub VIP</h3>
                        <p className="text-brand-100 max-w-lg">Chat privado, Feed Social, contos semanais e 50% de desconto.</p>
                    </div>
                </div>
                <div className="flex items-center gap-2 bg-white text-brand-900 px-6 py-3 rounded-xl font-bold">
                    Conhecer <ChevronRight size={16} />
                </div>
            </div>
        </section>
      )}

      {/* Filtro de Orientação */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 border-b border-dark-800 pb-4">
        <h2 className="text-xl font-bold text-white flex items-center gap-2">
           <Users size={20} className="text-gray-400" /> Filtrar Conteúdo:
        </h2>
        <div className="flex bg-dark-800 p-1 rounded-xl">
           <button 
             onClick={() => setActiveFilter('Homens')}
             className={`px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 transition-all ${activeFilter === 'Homens' ? 'bg-blue-900/50 text-blue-400 shadow' : 'text-gray-500 hover:text-gray-300'}`}
