          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {myCourses.map(fetish => (
              <div 
                key={fetish.id}
                onClick={() => onSelectUnlocked(fetish, activeFilter)}
                className="bg-dark-800 border border-brand-900/50 rounded-xl overflow-hidden hover:border-brand-500 transition-all cursor-pointer group shadow-lg"
              >
                <div className={`h-24 relative flex items-center px-6 bg-gradient-to-r ${fetish.color}`}>
                   <div className="bg-white/20 p-3 rounded-full backdrop-blur-sm">
                      {renderIcon(fetish.iconName)}
