                   <div className="ml-4">
                      <h3 className="text-xl font-bold text-white">{fetish.title}</h3>
                      <span className="text-[10px] bg-black/30 px-2 py-0.5 rounded text-white/80 uppercase font-bold tracking-wider">
                        Versão {activeFilter}
                      </span>
                   </div>
                </div>
                <div className="p-6">
                   <div className="w-full bg-dark-700 h-1.5 rounded-full overflow-hidden mb-4">
                      <div className="bg-brand-500 h-full w-0"></div>
                   </div>
                   <button className="w-full py-3 bg-dark-700 hover:bg-brand-600 text-white rounded-lg font-semibold transition-colors flex justify-center items-center gap-2">
                      <BookOpen size={16} /> Ler Guia
                   </button>
                </div>
              </div>
            ))}
          </div>
        </section>
      )}

      {/* Catálogo - Figurinhas */}
      <section>
        <h2 className="text-2xl font-bold text-white mb-6 flex items-center gap-2">
           <Star className="text-yellow-500" size={24} /> Catálogo ({activeFilter})
        </h2>
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4 md:gap-6">
          {exploreCourses.map(fetish => (
            <div 
              key={fetish.id}
              onClick={() => onSelectLocked(fetish, activeFilter)}
              className="bg-dark-800 border border-dark-700 rounded-2xl overflow-hidden hover:border-brand-500/50 hover:-translate-y-1 transition-all cursor-pointer group relative shadow-lg flex flex-col"
            >
                {/* Sticker Area */}
                <div className={`aspect-square relative flex flex-col items-center justify-center p-4 bg-gradient-to-br ${fetish.color} opacity-90 group-hover:opacity-100 transition-opacity`}>

                   <div className="bg-white/20 p-4 rounded-full backdrop-blur-md mb-2 shadow-inner">
                      {renderIcon(fetish.iconName, 40)}
                   </div>

                   <div className="absolute top-3 right-3 bg-black/40 px-2 py-1 rounded text-[10px] font-bold text-white flex items-center gap-1">
                      <Lock size={10} /> #{fetish.rank}
                   </div>
                </div>

                {/* Info Area */}
                <div className="p-4 flex-1 flex flex-col justify-between bg-dark-800">
                   <div>
                       <h3 className="text-sm md:text-lg font-bold text-white leading-tight mb-1">{fetish.title}</h3>
