    </div>
  );
};

export default Dashboard;

import React, { useEffect, useState } from 'react';
import { User, Crown, BookOpen, LogOut, ShieldCheck, Edit3, HelpCircle, MapPin, Calendar, Camera } from 'lucide-react';
import * as LucideIcons from 'lucide-react';
import { FETISH_DATA } from '../constants';
import { supabase } from '../lib/supabase';
import { UserProfile } from '../types';

interface Props {
  userEmail: string;
  isSubscribed: boolean;
  unlockedIds: string[];
  onLogout: () => void;
  onRead: (fetishId: string) => void;
  onOpenSubscribe: () => void;
}

const Profile: React.FC<Props> = ({ userEmail, isSubscribed, unlockedIds, onLogout, onRead, onOpenSubscribe }) => {
  const myCourses = FETISH_DATA.filter(f => unlockedIds.includes(f.id));
  const [profileData, setProfileData] = useState<UserProfile | null>(null);
  const [uploading, setUploading] = useState(false);

  useEffect(() => {
     if(supabase) {
        supabase.from('profiles').select('*').eq('email', userEmail).single().then(({data}) => {
            if(data) {
                setProfileData(data);
            }
        });
     }
  }, [userEmail]);

  const handleAvatarChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && supabase && profileData) {
        if (file.size > 500000) {
            alert("A imagem deve ser menor que 500KB.");
            return;
        }

        setUploading(true);
        // Convert to Base64 for simplicity in this demo environment
        const reader = new FileReader();
        reader.onloadend = async () => {
            const base64String = reader.result as string;

            const { error } = await supabase
                .from('profiles')
                .update({ avatar_url: base64String })
                .eq('id', profileData.id);

            if (!error) {
                setProfileData({ ...profileData, avatar_url: base64String });
            } else {
                alert("Erro ao atualizar foto.");
            }
            setUploading(false);
        };
        reader.readAsDataURL(file);
    }
  };

  const renderIcon = (iconName: string, size = 24) => {
    const Icon = (LucideIcons as any)[iconName] || HelpCircle;
    return <Icon size={size} className="text-white" />;
  };

  const getAge = (birthDate?: string) => {
      if (!birthDate) return '';
      const today = new Date();
      const birth = new Date(birthDate);
      let age = today.getFullYear() - birth.getFullYear();
      const m = today.getMonth() - birth.getMonth();
      if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) age--;
      return age;
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      {/* Header do Perfil */}
      <div className="bg-dark-800 rounded-2xl p-8 border border-dark-700 flex flex-col md:flex-row items-center gap-8 relative overflow-hidden">
        <div className="absolute top-0 right-0 p-32 bg-brand-900/20 blur-3xl rounded-full translate-x-10 -translate-y-10"></div>

        <div className="w-24 h-24 rounded-full bg-dark-700 border-2 border-brand-500 flex items-center justify-center shrink-0 relative z-10 group cursor-pointer">
           {profileData?.avatar_url ? (
              <img src={profileData.avatar_url} alt="Avatar" className="w-full h-full object-cover rounded-full" />
           ) : (
              <User size={40} className="text-gray-300" />
           )}

           {/* Edit Overlay */}
           <label className="absolute inset-0 bg-black/50 rounded-full flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity cursor-pointer">
              {uploading ? <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin"></div> : <Camera size={24} className="text-white" />}
              <input type="file" className="hidden" accept="image/*" onChange={handleAvatarChange} disabled={uploading} />
           </label>

           {isSubscribed && (
               <div className="absolute bottom-0 right-0 bg-brand-500 p-1 rounded-full border border-dark-900 pointer-events-none">
                   <Crown size={12} className="text-white" />
               </div>
           )}
        </div>

        <div className="text-center md:text-left flex-1 relative z-10">
           <h2 className="text-2xl font-bold text-white mb-1">{profileData?.full_name || "Usuário"}</h2>
           <p className="text-gray-400 font-mono text-sm mb-4">{userEmail}</p>

           <div className="flex flex-wrap gap-3 justify-center md:justify-start">
              <span className={`px-3 py-1 rounded-full text-xs font-bold border ${isSubscribed ? 'bg-brand-900/30 border-brand-500 text-brand-400' : 'bg-dark-700 border-dark-600 text-gray-400'}`}>
                  {isSubscribed ? 'Membro Club VIP' : 'Membro Gratuito'}
              </span>
              <span className="px-3 py-1 rounded-full text-xs font-bold bg-dark-700 border border-dark-600 text-gray-400">
                  {unlockedIds.length} Guias Adquiridos
              </span>
           </div>

           {/* Info Extra */}
           {profileData && (
              <div className="mt-4 text-xs text-gray-500 grid grid-cols-2 md:grid-cols-4 gap-4 max-w-lg mx-auto md:mx-0 border-t border-dark-700 pt-2">
                 <div>
                    <span className="block font-bold mb-1">Telefone</span>
                    <span>{profileData.phone}</span>
                 </div>
                 {profileData.city && (
                    <div className="col-span-2">
                        <span className="block font-bold mb-1">Localização</span>
                        <span className="flex items-center gap-1 justify-center md:justify-start">
                            <MapPin size={10} /> {profileData.city} - {profileData.state}
                        </span>
                    </div>
                 )}
                 {profileData.birth_date && (
                    <div>
                        <span className="block font-bold mb-1">Idade</span>
                        <span className="flex items-center gap-1 justify-center md:justify-start">
                            <Calendar size={10} /> {getAge(profileData.birth_date)} anos
                        </span>
                    </div>
                 )}
              </div>
           )}
        </div>

        <button 
           onClick={onLogout}
           className="px-4 py-2 bg-dark-900 hover:bg-red-900/30 border border-dark-600 hover:border-red-500/50 text-gray-400 hover:text-red-400 rounded-lg text-sm transition-all flex items-center gap-2 relative z-10"
        >
           <LogOut size={16} /> Sair
        </button>
      </div>

      {/* Seção de Assinatura */}
      {!isSubscribed && (
         <div className="bg-gradient-to-r from-brand-900/40 to-dark-800 border border-brand-900/50 rounded-2xl p-6 md:p-8 flex flex-col md:flex-row items-center justify-between gap-6">
            <div>
               <h3 className="text-xl font-bold text-white mb-2 flex items-center gap-2">
                  <Crown className="text-brand-500" size={24} /> Torne-se Membro Club
               </h3>
               <p className="text-gray-400 text-sm max-w-md">
                  Desbloqueie acesso ao Chat Privado, Feed de Fotos, receba contos exclusivos semanais e tenha 50% de desconto.
               </p>
            </div>
            <button 
                onClick={onOpenSubscribe}
                className="bg-brand-600 hover:bg-brand-500 text-white px-6 py-3 rounded-xl font-bold transition-colors whitespace-nowrap shadow-lg shadow-brand-900/20"
            >
                Ativar Assinatura VIP
            </button>
         </div>
      )}

      {/* Lista de Cursos */}
      <div>
         <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2 border-b border-dark-800 pb-4">
            <BookOpen size={20} className="text-brand-400" /> Meus Guias
         </h3>

         {myCourses.length > 0 ? (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
               {myCourses.map(fetish => (
                  <div key={fetish.id} className="bg-dark-800 rounded-xl p-4 border border-dark-700 flex gap-4 hover:border-brand-500/50 transition-colors group">
                     <div className={`w-16 h-16 rounded-lg shrink-0 flex items-center justify-center bg-gradient-to-br ${fetish.color}`}>
                         {renderIcon(fetish.iconName)}
                     </div>
                     <div className="flex-1 min-w-0">
                        <h4 className="font-bold text-white truncate group-hover:text-brand-400 transition-colors">{fetish.title}</h4>
                        <p className="text-xs text-green-500 flex items-center gap-1 mt-1">
                           <ShieldCheck size={12} /> Acesso Vitalício
                        </p>
                        <button 
                            onClick={() => onRead(fetish.id)}
                            className="text-xs text-gray-400 hover:text-white underline mt-2"
                        >
                            Continuar Leitura
                        </button>
                     </div>
                  </div>
               ))}
            </div>
         ) : (
            <div className="text-center py-12 bg-dark-800/30 rounded-xl border border-dashed border-dark-700">
               <p className="text-gray-500 mb-2">Sua biblioteca está vazia.</p>
               <p className="text-sm text-gray-600">Explore o catálogo para começar sua jornada.</p>
            </div>
         )}
      </div>
    </div>
  );
