import React, { useState, useEffect, useRef } from 'react';
import { Send, Lock, Crown, MoreVertical, MessageCircle, Image, Heart, Users, Search, Mail, Camera } from 'lucide-react';
import { supabase } from '../lib/supabase';

interface Props {
  isSubscribed: boolean;
  userEmail: string | null;
  onOpenSubscribe: () => void;
}

type Tab = 'lounge' | 'feed' | 'direct';

// --- SUB-COMPONENT: LOUNGE (Chat Temporário de 1h) ---
const LoungeChat: React.FC<{ userEmail: string; userProfile: any }> = ({ userEmail, userProfile }) => {
  const [messages, setMessages] = useState<any[]>([]);
  const [newMessage, setNewMessage] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages]);

  useEffect(() => {
    if (!supabase) return;

    // Busca apenas mensagens da última hora
    const oneHourAgo = new Date(Date.now() - 60 * 60 * 1000).toISOString();

    const fetchMessages = async () => {
      const { data } = await supabase
        .from('chat_messages')
        .select('*')
        .gte('created_at', oneHourAgo)
        .order('created_at', { ascending: true });
      if (data) setMessages(data);
    };

    fetchMessages();

    const channel = supabase
      .channel('public:chat_messages')
      .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'chat_messages' }, (payload) => {
        setMessages((prev) => [...prev, payload.new]);
      })
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, []);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newMessage.trim()) return;
    const text = newMessage;
    setNewMessage('');

    await supabase?.from('chat_messages').insert({
      user_email: userEmail,
      user_name: userProfile?.name,
      user_avatar: userProfile?.avatar,
      content: text
    });
  };

  return (
    <div className="flex flex-col h-full bg-dark-800">
      <div className="p-3 bg-dark-900 border-b border-dark-700 text-xs text-gray-500 flex justify-between items-center">
         <span>Mensagens somem após 1 hora.</span>
         <span className="flex items-center gap-1 text-green-500"><div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></div> Ao vivo</span>
      </div>
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.map((msg) => {
           const isMe = userEmail === msg.user_email;
           return (
             <div key={msg.id} className={`flex gap-3 ${isMe ? 'flex-row-reverse' : ''}`}>
                <div className="w-8 h-8 rounded-full bg-dark-700 overflow-hidden shrink-0">
                    {msg.user_avatar && <img src={msg.user_avatar} className="w-full h-full object-cover" />}
                </div>
                <div className={`max-w-[75%] p-3 rounded-2xl text-sm ${isMe ? 'bg-brand-600 text-white rounded-tr-none' : 'bg-dark-700 text-gray-200 rounded-tl-none'}`}>
                   <p className="font-bold text-[10px] mb-1 opacity-70">{msg.user_name}</p>
                   {msg.content}
                </div>
             </div>
           );
        })}
      </div>
      <form onSubmit={handleSend} className="p-4 bg-dark-900 border-t border-dark-700 flex gap-2">
         <input 
            className="flex-1 bg-dark-800 rounded-xl px-4 py-2 text-white border border-dark-600 focus:border-brand-500 outline-none" 
            placeholder="Digite algo..." 
            value={newMessage} 
            onChange={e => setNewMessage(e.target.value)}
         />
         <button className="bg-brand-600 p-2 rounded-xl text-white"><Send size={20}/></button>
      </form>
    </div>
  );
};

// --- SUB-COMPONENT: FEED (Instagram Style) ---
const SocialFeed: React.FC<{ userEmail: string; userProfile: any }> = ({ userEmail, userProfile }) => {
    const [posts, setPosts] = useState<any[]>([]);
    const [isPosting, setIsPosting] = useState(false);
    const [newImage, setNewImage] = useState<string | null>(null);
    const [caption, setCaption] = useState('');
    const [uploading, setUploading] = useState(false);

    useEffect(() => {
        if(!supabase) return;
        const fetchPosts = async () => {
            const { data } = await supabase.from('social_posts').select('*').order('created_at', { ascending: false }).limit(20);
            if(data) setPosts(data);
        };
        fetchPosts();

        const channel = supabase.channel('feed').on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'social_posts' }, (payload) => {
            setPosts(prev => [payload.new, ...prev]);
        }).subscribe();
        return () => { supabase.removeChannel(channel); };
    }, []);

    const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            if(file.size > 500000) return alert("Máximo 500kb");
            const reader = new FileReader();
            reader.onloadend = () => setNewImage(reader.result as string);
            reader.readAsDataURL(file);
        }
    };

    const handlePost = async () => {
        if(!newImage || !supabase) return;
        setUploading(true);
        const { error } = await supabase.from('social_posts').insert({
            user_name: userProfile?.name,
            user_avatar: userProfile?.avatar,
            image_url: newImage,
            caption: caption
        });
        setUploading(false);
        setIsPosting(false);
        setNewImage(null);
        setCaption('');
    };

    if(isPosting) {
        return (
            <div className="h-full bg-dark-800 p-4 flex flex-col">
                <h3 className="text-white font-bold mb-4">Novo Post</h3>
                <div className="flex-1 flex flex-col gap-4">
                    <label className="aspect-square bg-dark-700 rounded-xl flex items-center justify-center cursor-pointer border-2 border-dashed border-dark-600">
                        {newImage ? <img src={newImage} className="w-full h-full object-contain" /> : <div className="text-center text-gray-500"><Camera className="mx-auto mb-2"/>Foto</div>}
                        <input type="file" className="hidden" accept="image/*" onChange={handleImageUpload} />
                    </label>
                    <textarea 
                        className="bg-dark-900 w-full p-3 rounded-xl text-white resize-none h-24 border border-dark-700" 
                        placeholder="Legenda..." 
                        value={caption} 
                        onChange={e => setCaption(e.target.value)}
                    />
                </div>
                <div className="flex gap-2 mt-4">
                    <button onClick={() => setIsPosting(false)} className="flex-1 py-3 bg-dark-700 text-white rounded-xl">Cancelar</button>
                    <button onClick={handlePost} disabled={!newImage || uploading} className="flex-1 py-3 bg-brand-600 text-white rounded-xl font-bold">Postar</button>
                </div>
            </div>
        );
    }

    return (
        <div className="h-full bg-dark-900 relative overflow-y-auto">
            <div className="sticky top-0 z-10 bg-dark-900/90 backdrop-blur p-4 border-b border-dark-800 flex justify-between items-center">
                <h3 className="font-bold text-white text-lg">Club Feed</h3>
                <button onClick={() => setIsPosting(true)} className="bg-brand-600 p-2 rounded-lg text-white"><Camera size={20}/></button>
            </div>
            <div className="pb-20">
                {posts.map(post => (
                    <div key={post.id} className="mb-6 bg-dark-800 pb-4 border-b border-dark-700">
                        <div className="flex items-center gap-3 p-3">
                            <div className="w-8 h-8 rounded-full bg-dark-700 overflow-hidden">
                                {post.user_avatar && <img src={post.user_avatar} className="w-full h-full object-cover" />}
                            </div>
                            <span className="font-bold text-white text-sm">{post.user_name}</span>
                        </div>
                        <img src={post.image_url} className="w-full max-h-96 object-cover bg-black" />
                        <div className="px-3 pt-3">
                            <div className="flex gap-4 mb-2">
                                <Heart className="text-white hover:text-red-500 cursor-pointer transition-colors" />
                            </div>
                            <p className="text-sm text-gray-300"><span className="font-bold text-white mr-2">{post.user_name}</span>{post.caption}</p>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
};

// --- SUB-COMPONENT: DIRECT (WhatsApp Style) ---
const DirectChat: React.FC<{ userEmail: string }> = ({ userEmail }) => {
    const [view, setView] = useState<'list' | 'chat'>('list');
    const [selectedUser, setSelectedUser] = useState<any>(null);
    const [users, setUsers] = useState<any[]>([]);
    const [messages, setMessages] = useState<any[]>([]);
    const [newMessage, setNewMessage] = useState('');
    const [searchTerm, setSearchTerm] = useState('');
    const scrollRef = useRef<HTMLDivElement>(null);

    // Fetch user list (Simulação: Pega perfis que aceitaram termos ou tem avatar)
    useEffect(() => {
        if(!supabase) return;
        const fetchUsers = async () => {
             // Em produção, isso seria uma query mais complexa ou uma tabela de 'amigos'
             // Aqui, listamos usuários recentes para demo
             const { data } = await supabase.from('profiles').select('id, full_name, avatar_url, email').neq('email', userEmail).limit(20);
             if(data) setUsers(data);
        };
        fetchUsers();
    }, []);

    // Fetch messages for selected user
    useEffect(() => {
        if(!supabase || !selectedUser || view !== 'chat') return;

        const fetchMessages = async () => {
             const { data: { user: currentUser } } = await supabase!.auth.getUser();
             if(!currentUser) return;

             const { data } = await supabase.from('private_messages')
                .select('*')
                .or(`and(sender_id.eq.${currentUser.id},receiver_id.eq.${selectedUser.id}),and(sender_id.eq.${selectedUser.id},receiver_id.eq.${currentUser.id})`)
                .order('created_at', { ascending: true });

             if(data) setMessages(data);
        };
        fetchMessages();

        const channel = supabase.channel('direct').on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'private_messages' }, (payload) => {
            const msg = payload.new;
            if(msg.sender_id === selectedUser.id || msg.receiver_id === selectedUser.id) {
                setMessages(prev => [...prev, msg]);
            }
        }).subscribe();

        return () => { supabase.removeChannel(channel); };
    }, [selectedUser, view]);

    useEffect(() => {
       if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }, [messages]);

    const handleSend = async (e: React.FormEvent) => {
        e.preventDefault();
        if(!newMessage.trim() || !supabase) return;
        const { data: { user: currentUser } } = await supabase.auth.getUser();
        if(!currentUser) return;

        await supabase.from('private_messages').insert({
            sender_id: currentUser.id,
            receiver_id: selectedUser.id,
            content: newMessage
        });
        setNewMessage('');
    };

    if (view === 'list') {
        const filtered = users.filter(u => (u.full_name || 'User').toLowerCase().includes(searchTerm.toLowerCase()));
        return (
            <div className="h-full bg-dark-900 flex flex-col">
                <div className="p-4 border-b border-dark-800">
                    <h3 className="font-bold text-white text-lg mb-4">Direct</h3>
                    <div className="relative">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={16}/>
                        <input 
                            className="w-full bg-dark-800 rounded-xl py-2 pl-9 text-white border border-dark-700 focus:border-brand-500 outline-none"
                            placeholder="Buscar membro..."
                            value={searchTerm}
                            onChange={e => setSearchTerm(e.target.value)}
                        />
                    </div>
                </div>
                <div className="flex-1 overflow-y-auto">
                    {filtered.map(u => (
                        <div key={u.id} onClick={() => { setSelectedUser(u); setView('chat'); }} className="p-4 flex items-center gap-4 hover:bg-dark-800 cursor-pointer border-b border-dark-800 transition-colors">
                            <div className="w-12 h-12 rounded-full bg-dark-700 overflow-hidden">
                                {u.avatar_url ? <img src={u.avatar_url} className="w-full h-full object-cover" /> : <div className="w-full h-full flex items-center justify-center text-gray-500"><Users size={20}/></div>}
                            </div>
                            <div>
                                <h4 className="font-bold text-white">{u.full_name || 'Membro Kink'}</h4>
                                <p className="text-xs text-gray-500">Toque para conversar</p>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        );
    }

    return (
        <div className="h-full bg-dark-900 flex flex-col">
            <div className="p-3 bg-dark-800 border-b border-dark-700 flex items-center gap-3">
                <button onClick={() => setView('list')} className="text-gray-400 hover:text-white">Voltar</button>
                <div className="w-8 h-8 rounded-full bg-dark-700 overflow-hidden">
                    {selectedUser.avatar_url && <img src={selectedUser.avatar_url} className="w-full h-full object-cover" />}
                </div>
                <span className="font-bold text-white">{selectedUser.full_name}</span>
            </div>
            <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-3 bg-black/20">
                {messages.map(msg => {
                    const isMe = msg.sender_id !== selectedUser.id; // Se não foi o selecionado que enviou, fui eu
                    return (
                        <div key={msg.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'}`}>
                            <div className={`max-w-[80%] p-3 rounded-2xl text-sm ${isMe ? 'bg-brand-700 text-white rounded-tr-none' : 'bg-dark-700 text-gray-200 rounded-tl-none'}`}>
                                {msg.content}
                            </div>
                        </div>
                    );
                })}
            </div>
            <form onSubmit={handleSend} className="p-3 bg-dark-800 flex gap-2">
                <input 
                    className="flex-1 bg-dark-900 rounded-xl px-4 py-2 text-white border border-dark-600 outline-none"
                    placeholder="Mensagem..."
                    value={newMessage}
                    onChange={e => setNewMessage(e.target.value)}
                />
                <button className="bg-brand-600 p-2 rounded-xl text-white"><Send size={20}/></button>
            </form>
        </div>
    );
};

