                <div className={`h-24 relative flex items-center px-6 bg-gradient-to-r ${fetish.color}`}>
                   <div className="bg-white/20 p-3 rounded-full backdrop-blur-sm">
                      {renderIcon(fetish.iconName)}
                   </div>
                   <div className="ml-4">
                      <h3 className="text-xl font-bold text-white">{fetish.title}</h3>
                      <span className="text-[10px] bg-black/30 px-2 py-0.5 rounded text-white/80 uppercase font-bold tracking-wider">
                        Versão {activeFilter}
                      </span>
                   </div>
                </div>
                <div className="p-6">
                   <div className="w-full bg-dark-700 h-1.5 rounded-full overflow-hidden mb-4">
                      <div className="bg-brand-500 h-full w-0"></div>
                   </div>
                   <button className="w-full py-3 bg-dark-700 hover:bg-brand-600 text-white rounded-lg font-semibold transition-colors flex justify-center items-center gap-2">
                      <BookOpen size={16} /> Ler Guia
                   </button>
                </div>
              </div>
            ))}
          </div>
        </section>
      )}

      {/* Catálogo - Figurinhas - ATUALIZADO (IMAGEM MENOR, TEXTO MAIOR) */}
      <section>
        <h2 className="text-2xl font-bold text-white mb-6 flex items-center gap-2">
           <Star className="text-yellow-500" size={24} /> Catálogo ({activeFilter})
        </h2>

        {/* Usando grid com cards mais compactos na altura da imagem */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6">
          {exploreCourses.map(fetish => (
            <div 
              key={fetish.id}
              onClick={() => onSelectLocked(fetish, activeFilter)}
              className="bg-dark-800 border border-dark-700 rounded-xl overflow-hidden hover:border-brand-500/50 hover:shadow-brand-900/20 hover:-translate-y-1 transition-all cursor-pointer group relative shadow-lg flex flex-col"
            >
                {/* Image Area - Reduzido (h-24 em vez de aspect-square) */}
                <div className={`h-24 relative flex items-center justify-between px-6 bg-gradient-to-r ${fetish.color} opacity-90 group-hover:opacity-100 transition-opacity`}>
                   <div className="bg-white/20 p-2 rounded-full backdrop-blur-md shadow-inner">
                      {renderIcon(fetish.iconName, 28)}
                   </div>
                   <div className="bg-black/30 px-3 py-1 rounded text-xs font-bold text-white flex items-center gap-1 backdrop-blur-sm">
                      <Lock size={12} /> #{fetish.rank}
                   </div>
                </div>

                {/* Info Area - Ampliado */}
                <div className="p-6 flex-1 flex flex-col justify-between bg-dark-800">
                   <div>
                       {/* Título Grande */}
                       <h3 className="text-xl md:text-2xl font-black text-white leading-tight mb-3 group-hover:text-brand-400 transition-colors">
                          {fetish.title}
                       </h3>

                       {/* Texto Descritivo Maior */}
                       <p className="text-sm md:text-base text-gray-400 leading-relaxed font-medium">
                          {getStatText(fetish)}
                       </p>
                   </div>

                   <div className="mt-6 pt-4 border-t border-dark-700 flex justify-between items-center">
                      <div>
                        {isSubscribed && <span className="block text-xs text-green-400 line-through mb-0.5">R$ 47</span>}
                        <span className={`text-lg font-black text-white ${isSubscribed ? 'text-green-400' : ''}`}>
                            R$ {isSubscribed ? '23' : '47'}
                        </span>
                      </div>
                      <button className="bg-dark-700 p-2 rounded-full group-hover:bg-brand-600 transition-colors text-white">
                        <ChevronRight size={20} />
                      </button>
                   </div>
                </div>
            </div>
          ))}
        </div>
      </section>
    </div>
  );
};

export default Dashboard;

